const DEFAULT_VERSES=[{"book":"요한계시록","chapter":1,"verse":1,"text":"예수 그리스도의 계시라 이는 하나님이 그에게 주사 반드시 속히 될 일을 그 종들에게 보이시려고 그 천사를 그 종 요한에게 보내어 지시하신 것이라"},{"book":"요한계시록","chapter":1,"verse":2,"text":"요한은 하나님의 말씀과 예수 그리스도의 증거 곧 자기의 본 것을 다 증거하였느니라"},{"book":"요한계시록","chapter":1,"verse":3,"text":"이 예언의 말씀을 읽는 자와 듣는 자들과 그 가운데 기록한 것을 지키는 자들이 복이 있나니 때가 가까움이라"},{"book":"요한계시록","chapter":1,"verse":4,"text":"요한은 아시아에 있는 일곱 교회에 편지하노니 이제도 계시고 전에도 계시고 장차 오실 이와 그 보좌 앞에 일곱 영과"},{"book":"요한계시록","chapter":1,"verse":5,"text":"또 충성된 증인으로 죽은 자들 가운데서 먼저 나시고 땅의 임금들의 머리가 되신 예수 그리스도로 말미암아 은혜와 평강이 너희에게 있기를 원하노라 우리를 사랑하사 그의 피로 우리 죄에서 우리를 해방하시고"},{"book":"요한계시록","chapter":1,"verse":6,"text":"그 아버지 하나님을 위하여 우리를 나라와 제사장으로 삼으신 그에게 영광과 능력이 세세토록 있기를 원하노라 아멘"},{"book":"요한계시록","chapter":1,"verse":7,"text":"볼찌어다 구름을 타고 오시리라 각인의 눈이 그를 보겠고 그를 찌른 자들도 볼터이요 땅에 있는 모든 족속이 그를 인하여 애곡하리니 그러하리라 아멘"},{"book":"요한계시록","chapter":1,"verse":8,"text":"주 하나님이 가라사대 나는 알파와 오메가라 이제도 있고 전에도 있었고 장차 올 자요 전능한 자라 하시더라"},{"book":"요한계시록","chapter":1,"verse":9,"text":"나 요한은 너희 형제요 예수의 환난과 나라와 참음에 동참하는 자라 하나님의 말씀과 예수의 증거를 인하여 밧모라 하는 섬에 있었더니"},{"book":"요한계시록","chapter":1,"verse":10,"text":"주의 날에 내가 성령에 감동하여 내 뒤에서 나는 나팔 소리 같은 큰 음성을 들으니"},{"book":"요한계시록","chapter":1,"verse":11,"text":"가로되 너 보는 것을 책에 써서 에베소, 서머나, 버가모, 두아디라, 사데, 빌라델비아, 라오디게아 일곱 교회에 보내라 하시기로"},{"book":"요한계시록","chapter":1,"verse":12,"text":"몸을 돌이켜 나더러 말한 음성을 알아 보려고 하여 돌이킬 때에 일곱 금 촛대를 보았는데"},{"book":"요한계시록","chapter":1,"verse":13,"text":"촛대 사이에 인자 같은 이가 발에 끌리는 옷을 입고 가슴에 금띠를 띠고"},{"book":"요한계시록","chapter":1,"verse":14,"text":"그 머리와 털의 희기가 흰 양털 같고 눈 같으며 그의 눈은 불꽃 같고"},{"book":"요한계시록","chapter":1,"verse":15,"text":"그의 발은 풀무에 단련한 빛난 주석 같고 그의 음성은 많은 물 소리와 같으며"},{"book":"요한계시록","chapter":1,"verse":16,"text":"그 오른손에 일곱 별이 있고 그 입에서 좌우에 날선 검이 나오고 그 얼굴은 해가 힘있게 비취는것 같더라"},{"book":"요한계시록","chapter":1,"verse":17,"text":"내가 볼때에 그 발앞에 엎드러져 죽은 자 같이 되매 그가 오른손을 내게 얹고 가라사대 두려워 말라 나는 처음이요 나중이니"},{"book":"요한계시록","chapter":1,"verse":18,"text":"곧 산 자라 내가 전에 죽었었노라 볼찌어다 이제 세세토록 살아 있어 사망과 음부의 열쇠를 가졌노니"},{"book":"요한계시록","chapter":1,"verse":19,"text":"그러므로 네 본 것과 이제 있는 일과 장차 될 일을 기록하라"},{"book":"요한계시록","chapter":1,"verse":20,"text":"네 본 것은 내 오른손에 일곱 별의 비밀과 일곱 금 촛대라 일곱 별은 일곱 교회의 사자요 일곱 촛대는 일곱 교회니라"},{"book":"요한계시록","chapter":2,"verse":1,"text":"에베소 교회의 사자에게 편지하기를 오른손에 일곱 별을 붙잡고 일곱 금 촛대 사이에 다니시는 이가 가라사대"},{"book":"요한계시록","chapter":2,"verse":2,"text":"내가 네 행위와 수고와 네 인내를 알고 또 악한 자들을 용납지 아니한 것과 자칭 사도라 하되 아닌 자들을 시험하여 그 거짓된 것을 네가 드러낸 것과"},{"book":"요한계시록","chapter":2,"verse":3,"text":"또 네가 참고 내 이름을 위하여 견디고 게으르지 아니한 것을 아노라"},{"book":"요한계시록","chapter":2,"verse":4,"text":"그러나 너를 책망할 것이 있나니 너의 처음 사랑을 버렸느니라"},{"book":"요한계시록","chapter":2,"verse":5,"text":"그러므로 어디서 떨어진 것을 생각하고 회개하여 처음 행위를 가지라 만일 그리하지 아니하고 회개치 아니하면 내가 네게 임하여 네 촛대를 그 자리에서 옮기리라"},{"book":"요한계시록","chapter":2,"verse":6,"text":"오직 네게 이것이 있으니 네가 니골라당의 행위를 미워하는도다 나도 이것을 미워하노라"},{"book":"요한계시록","chapter":2,"verse":7,"text":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을찌어다 이기는 그에게는 내가 하나님의 낙원에 있는 생명나무의 과실을 주어 먹게 하리라"},{"book":"요한계시록","chapter":2,"verse":8,"text":"서머나 교회의 사자에게 편지하기를 처음이요 나중이요 죽었다가 살아나신 이가 가라사대"},{"book":"요한계시록","chapter":2,"verse":9,"text":"내가 네 환난과 궁핍을 아노니 실상은 네가 부요한 자니라 자칭 유대인이라 하는 자들의 훼방도 아노니 실상은 유대인이 아니요 사단의 회라"},{"book":"요한계시록","chapter":2,"verse":10,"text":"네가 장차 받을 고난을 두려워 말라 볼찌어다 마귀가 장차 너희 가운데서 몇 사람을 옥에 던져 시험을 받게 하리니 너희가 십일 동안 환난을 받으리라 네가 죽도록 충성하라 그리하면 내가 생명의 면류관을 네게 주리라"},{"book":"요한계시록","chapter":2,"verse":11,"text":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을찌어다 이기는 자는 둘째 사망의 해를 받지 아니하리라"},{"book":"요한계시록","chapter":2,"verse":12,"text":"버가모 교회의 사자에게 편지하기를 좌우에 날선 검을 가진 이가 가라사대"},{"book":"요한계시록","chapter":2,"verse":13,"text":"네가 어디 사는 것을 내가 아노니 거기는 사단의 위가 있는 데라 네가 내 이름을 굳게 잡아서 내 충성된 증인 안디바가 너희 가운데 곧 사단의 거하는 곳에서 죽임을 당할 때에도 나를 믿는 믿음을 저버리지 아니하였도다"},{"book":"요한계시록","chapter":2,"verse":14,"text":"그러나 네게 두어가지 책망할 것이 있나니 거기 네게 발람의 교훈을 지키는 자들이 있도다 발람이 발락을 가르쳐 이스라엘 앞에 올무를 놓아 우상의 제물을 먹게 하였고 또 행음하게 하였느니라"},{"book":"요한계시록","chapter":2,"verse":15,"text":"이와 같이 네게도 니골라당의 교훈을 지키는 자들이 있도다"},{"book":"요한계시록","chapter":2,"verse":16,"text":"그러므로 회개하라 그리하지 아니하면 내가 네게 속히 임하여 내 입의 검으로 그들과 싸우리라"},{"book":"요한계시록","chapter":2,"verse":17,"text":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을찌어다 이기는 그에게는 내가 감추었던 만나를 주고 또 흰 돌을 줄터인데 그 돌 위에 새 이름을 기록한 것이 있나니 받는 자 밖에는 그 이름을 알 사람이 없느니라"},{"book":"요한계시록","chapter":2,"verse":18,"text":"두아디라 교회의 사자에게 편지하기를 그 눈이 불꽃 같고 그 발이 빛난 주석과 같은 하나님의 아들이 가라사대"},{"book":"요한계시록","chapter":2,"verse":19,"text":"내가 네 사업과 사랑과 믿음과 섬김과 인내를 아노니 네 나중 행위가 처음것보다 많도다"},{"book":"요한계시록","chapter":2,"verse":20,"text":"그러나 네게 책망할 일이 있노라 자칭 선지자라 하는 여자 이세벨을 네가 용납함이니 그가 내 종들을 가르쳐 꾀어 행음하게 하고 우상의 제물을 먹게 하는도다"},{"book":"요한계시록","chapter":2,"verse":21,"text":"또 내가 그에게 회개할 기회를 주었으되 그 음행을 회개하고자 아니하는도다"},{"book":"요한계시록","chapter":2,"verse":22,"text":"볼찌어다 내가 그를 침상에 던질터이요 또 그로 더불어 간음하는 자들도 만일 그의 행위를 회개치 아니하면 큰 환난 가운데 던지고"},{"book":"요한계시록","chapter":2,"verse":23,"text":"또 내가 사망으로 그의 자녀를 죽이리니 모든 교회가 나는 사람의 뜻과 마음을 살피는 자인줄 알찌라 내가 너희 각 사람의 행위대로 갚아 주리라"},{"book":"요한계시록","chapter":2,"verse":24,"text":"두아디라에 남아 있어 이 교훈을 받지 아니하고 소위 사단의 깊은 것을 알지 못하는 너희에게 말하노니 다른 짐으로 너희에게 지울 것이 없노라"},{"book":"요한계시록","chapter":2,"verse":25,"text":"다만 너희에게 있는 것을 내가 올 때까지 굳게 잡으라"},{"book":"요한계시록","chapter":2,"verse":26,"text":"이기는 자와 끝까지 내 일을 지키는 그에게 만국을 다스리는 권세를 주리니"},{"book":"요한계시록","chapter":2,"verse":27,"text":"그가 철장을 가지고 저희를 다스려 질그릇 깨뜨리는 것과 같이 하리라 나도 내 아버지께 받은 것이 그러하니라"},{"book":"요한계시록","chapter":2,"verse":28,"text":"내가 또 그에게 새벽 별을 주리라"},{"book":"요한계시록","chapter":2,"verse":29,"text":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을찌어다"},{"book":"요한계시록","chapter":3,"verse":1,"text":"사데 교회의 사자에게 편지하기를 하나님의 일곱 영과 일곱 별을 가진이가 가라사대 내가 네 행위를 아노니 네가 살았다 하는 이름은 가졌으나 죽은 자로다"},{"book":"요한계시록","chapter":3,"verse":2,"text":"너는 일깨워 그 남은바 죽게 된 것을 굳게 하라 내 하나님 앞에 네 행위의 온전한 것을 찾지 못하였노니"},{"book":"요한계시록","chapter":3,"verse":3,"text":"그러므로 네가 어떻게 받았으며 어떻게 들었는지 생각하고 지키어 회개하라 만일 일깨지 아니하면 내가 도적 같이 이르리니 어느 시에 네게 임할는지 네가 알지 못하리라"},{"book":"요한계시록","chapter":3,"verse":4,"text":"그러나 사데에 그 옷을 더럽히지 아니한 자 몇명이 네게 있어 흰 옷을 입고 나와 함께 다니리니 그들은 합당한 자인 연고라"},{"book":"요한계시록","chapter":3,"verse":5,"text":"이기는 자는 이와 같이 흰 옷을 입을 것이요 내가 그 이름을 생명책에서 반드시 흐리지 아니하고 그 이름을 내 아버지 앞과 그 천사들 앞에서 시인하리라"},{"book":"요한계시록","chapter":3,"verse":6,"text":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을찌어다"},{"book":"요한계시록","chapter":3,"verse":7,"text":"빌라델비아 교회의 사자에게 편지하기를 거룩하고 진실하사 다윗의 열쇠를 가지신 이 곧 열면 닫을 사람이 없고 닫으면 열 사람이 없는 그이가 가라사대"},{"book":"요한계시록","chapter":3,"verse":8,"text":"볼찌어다 내가 네 앞에 열린 문을 두었으되 능히 닫을 사람이 없으리라 내가 네 행위를 아노니 네가 적은 능력을 가지고도 내 말을 지키며 내 이름을 배반치 아니하였도다"},{"book":"요한계시록","chapter":3,"verse":9,"text":"보라 사단의 회 곧 자칭 유대인이라 하나 그렇지 않고 거짓말 하는 자들 중에서 몇을 네게 주어 저희로 와서 네 발앞에 절하게 하고 내가 너를 사랑하는 줄을 알게 하리라"},{"book":"요한계시록","chapter":3,"verse":10,"text":"네가 나의 인내의 말씀을 지켰은즉 내가 또한 너를 지키어 시험의 때를 면하게 하리니 이는 장차 온 세상에 임하여 땅에 거하는 자들을 시험할 때라"},{"book":"요한계시록","chapter":3,"verse":11,"text":"내가 속히 임하리니 네가 가진 것을 굳게 잡아 아무나 네 면류관을 빼앗지 못하게 하라"},{"book":"요한계시록","chapter":3,"verse":12,"text":"이기는 자는 내 하나님 성전에 기둥이 되게 하리니 그가 결코 다시 나가지 아니하리라 내가 하나님의 이름과 하나님의 성 곧 하늘에서 내 하나님께로부터 내려 오는 새 예루살렘의 이름과 나의 새 이름을 그이 위에 기록하리라"},{"book":"요한계시록","chapter":3,"verse":13,"text":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을찌어다"},{"book":"요한계시록","chapter":3,"verse":14,"text":"라오디게아 교회의 사자에게 편지하기를 아멘이시요 충성되고 참된 증인이시요 하나님의 창조의 근본이신 이가 가라사대"},{"book":"요한계시록","chapter":3,"verse":15,"text":"내가 네 행위를 아노니 네가 차지도 아니하고 더웁지도 아니하도다 네가 차든지 더웁든지 하기를 원하노라"},{"book":"요한계시록","chapter":3,"verse":16,"text":"네가 이같이 미지근하여 더웁지도 아니하고 차지도 아니하니 내 입에서 너를 토하여 내치리라"},{"book":"요한계시록","chapter":3,"verse":17,"text":"네가 말하기를 나는 부자라 부요하여 부족한 것이 없다 하나 네 곤고한 것과 가련한 것과 가난한 것과 눈 먼것과 벌거벗은 것을 알지 못하도다"},{"book":"요한계시록","chapter":3,"verse":18,"text":"내가 너를 권하노니 내게서 불로 연단한 금을 사서 부요하게 하고 흰 옷을 사서 입어 벌거벗은 수치를 보이지 않게 하고 안약을 사서 눈에 발라 보게 하라"},{"book":"요한계시록","chapter":3,"verse":19,"text":"무릇 내가 사랑하는 자를 책망하여 징계하노니 그러므로 네가 열심을 내라 회개하라"},{"book":"요한계시록","chapter":3,"verse":20,"text":"볼찌어다 내가 문밖에 서서 두드리노니 누구든지 내 음성을 듣고 문을 열면 내가 그에게로 들어가 그로 더불어 먹고 그는 나로 더불어 먹으리라"},{"book":"요한계시록","chapter":3,"verse":21,"text":"이기는 그에게는 내가 내 보좌에 함께 앉게 하여주기를 내가 이기고 아버지 보좌에 함께 앉은 것과 같이 하리라"},{"book":"요한계시록","chapter":3,"verse":22,"text":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을찌어다"},{"book":"요한계시록","chapter":4,"verse":1,"text":"이 일 후에 내가 보니 하늘에 열린 문이 있는데 내가 들은바 처음에 내게 말하던 나팔소리 같은 그 음성이 가로되 이리로 올라오라 이 후에 마땅히 될 일을 내가 네게 보이리라 하시더라"},{"book":"요한계시록","chapter":4,"verse":2,"text":"내가 곧 성령에 감동하였더니 보라 하늘에 보좌를 베풀었고 그 보좌 위에 앉으신 이가 있는데"},{"book":"요한계시록","chapter":4,"verse":3,"text":"앉으신 이의 모양이 벽옥과 홍보석 같고 또 무지개가 있어 보좌에 둘렸는데 그 모양이 녹보석 같더라"},{"book":"요한계시록","chapter":4,"verse":4,"text":"또 보좌에 둘려 이십 사 보좌들이 있고 그 보좌들 위에 이십 사 장로들이 흰 옷을 입고 머리에 금 면류관을 쓰고 앉았더라"},{"book":"요한계시록","chapter":4,"verse":5,"text":"보좌로부터 번개와 음성과 뇌성이 나고 보좌 앞에 일곱 등불 켠것이 있으니 이는 하나님의 일곱 영이라"},{"book":"요한계시록","chapter":4,"verse":6,"text":"보좌 앞에 수정과 같은 유리 바다가 있고 보좌 가운데와 보좌 주위에 네 생물이 있는데 앞뒤에 눈이 가득하더라"},{"book":"요한계시록","chapter":4,"verse":7,"text":"그 첫째 생물은 사자 같고 그 둘째 생물은 송아지 같고 그 세째 생물은 얼굴이 사람 같고 그 네째 생물은 날아가는 독수리 같은데"},{"book":"요한계시록","chapter":4,"verse":8,"text":"네 생물이 각각 여섯 날개가 있고 그 안과 주위에 눈이 가득하더라 그들이 밤낮 쉬지 않고 이르기를 거룩하다 거룩하다 거룩하다 주 하나님 곧 전능하신이여 전에도 계셨고 이제도 계시고 장차 오실 자라 하고"},{"book":"요한계시록","chapter":4,"verse":9,"text":"그 생물들이 영광과 존귀와 감사를 보좌에 앉으사 세세토록 사시는 이에게 돌릴 때에"},{"book":"요한계시록","chapter":4,"verse":10,"text":"이십 사 장로들이 보좌에 앉으신 이 앞에 엎드려 세세토록 사시는 이에게 경배하고 자기의 면류관을 보좌 앞에 던지며 가로되"},{"book":"요한계시록","chapter":4,"verse":11,"text":"우리 주 하나님이여 영광과 존귀와 능력을 받으시는 것이 합당하오니 주께서 만물을 지으신지라 만물이 주의 뜻대로 있었고 또 지으심을 받았나이다 하더라"},{"book":"요한계시록","chapter":5,"verse":1,"text":"내가 보매 보좌에 앉으신 이의 오른손에 책이 있으니 안팎으로 썼고 일곱 인으로 봉하였더라"},{"book":"요한계시록","chapter":5,"verse":2,"text":"또 보매 힘 있는 천사가 큰 음성으로 외치기를 누가 책을 펴며 그 인을 떼기에 합당하냐 하니"},{"book":"요한계시록","chapter":5,"verse":3,"text":"하늘 위에나 땅 위에나 땅 아래에 능히 책을 펴거나 보거나 할 이가 없더라"},{"book":"요한계시록","chapter":5,"verse":4,"text":"이 책을 펴거나 보거나 하기에 합당한 자가 보이지 않기로 내가 크게 울었더니"},{"book":"요한계시록","chapter":5,"verse":5,"text":"장로 중에 하나가 내게 말하되 울지 말라 유대 지파의 사자 다윗의 뿌리가 이기었으니 이 책과 그 일곱 인을 떼시리라 하더라"},{"book":"요한계시록","chapter":5,"verse":6,"text":"내가 또 보니 보좌와 네 생물과 장로들 사이에 어린 양이 섰는데 일찍 죽임을 당한것 같더라 일곱 뿔과 일곱 눈이 있으니 이 눈은 온 땅에 보내심을 입은 하나님의 일곱 영이더라"},{"book":"요한계시록","chapter":5,"verse":7,"text":"어린 양이 나아와서 보좌에 앉으신 이의 오른손에서 책을 취하시니라"},{"book":"요한계시록","chapter":5,"verse":8,"text":"책을 취하시매 네 생물과 이십 사 장로들이 어린 양 앞에 엎드려 각각 거문고와 향이 가득한 금 대접을 가졌으니 이 향은 성도의 기도들이라"},{"book":"요한계시록","chapter":5,"verse":9,"text":"새 노래를 노래하여 가로되 책을 가지시고 그 인봉을 떼기에 합당하시도다 일찍 죽임을 당하사 각 족속과 방언과 백성과 나라 가운데서 사람들을 피로 사서 하나님께 드리시고"},{"book":"요한계시록","chapter":5,"verse":10,"text":"저희로 우리 하나님 앞에서 나라와 제사장을 삼으셨으니 저희가 땅에서 왕노릇하리로다 하더라"},{"book":"요한계시록","chapter":5,"verse":11,"text":"내가 또 보고 들으매 보좌와 생물들과 장로들을 둘러 선 많은 천사의 음성이 있으니 그 수가 만만이요 천천이라"},{"book":"요한계시록","chapter":5,"verse":12,"text":"큰 음성으로 가로되 죽임을 당하신 어린 양이 능력과 부와 지혜와 힘과 존귀와 영광과 찬송을 받으시기에 합당하도다 하더라"},{"book":"요한계시록","chapter":5,"verse":13,"text":"내가 또 들으니 하늘 위에와 땅 위에와 땅 아래와 바다 위에와 또 그 가운데 모든 만물이 가로되 보좌에 앉으신 이와 어린 양에게 찬송과 존귀와 영광과 능력을 세세토록 돌릴찌어다 하니"},{"book":"요한계시록","chapter":5,"verse":14,"text":"네 생물이 가로되 아멘 하고 장로들은 엎드려 경배하더라"},{"book":"요한계시록","chapter":6,"verse":1,"text":"내가 보매 어린 양이 일곱 인 중에 하나를 떼시는 그 때에 내가 들으니 네 생물 중에 하나가 우뢰소리 같이 말하되 오라 하기로"},{"book":"요한계시록","chapter":6,"verse":2,"text":"내가 이에 보니 흰 말이 있는데 그 탄 자가 활을 가졌고 면류관을 받고 나가서 이기고 또 이기려고 하더라"},{"book":"요한계시록","chapter":6,"verse":3,"text":"둘째 인을 떼실 때에 내가 들으니 둘째 생물이 말하되 오라 하더니"},{"book":"요한계시록","chapter":6,"verse":4,"text":"이에 붉은 다른 말이 나오더라 그 탄 자가 허락을 받아 땅에서 화평을 제하여 버리며 서로 죽이게 하고 또 큰 칼을 받았더라"},{"book":"요한계시록","chapter":6,"verse":5,"text":"세째 인을 떼실 때에 내가 들으니 세째 생물이 말하되 오라 하기로 내가 보니 검은 말이 나오는데 그 탄 자가 손에 저울을 가졌더라"},{"book":"요한계시록","chapter":6,"verse":6,"text":"내가 네 생물 사이로서 나는듯하는 음성을 들으니 가로되 한 데나리온에 밀 한되요 한 데나리온에 보리 석되로다 또 감람유와 포도주는 해치 말라 하더라"},{"book":"요한계시록","chapter":6,"verse":7,"text":"네째 인을 떼실 때에 내가 네째 생물의 음성을 들으니 가로되 오라 하기로"},{"book":"요한계시록","chapter":6,"verse":8,"text":"내가 보매 청황색 말이 나오는데 그 탄 자의 이름은 사망이니 음부가 그 뒤를 따르더라 저희가 땅 사분 일의 권세를 얻어 검과 흉년과 사망과 땅의 짐승으로써 죽이더라"},{"book":"요한계시록","chapter":6,"verse":9,"text":"다섯째 인을 떼실 때에 내가 보니 하나님의 말씀과 저희의 가진 증거를 인하여 죽임을 당한 영혼들이 제단 아래 있어"},{"book":"요한계시록","chapter":6,"verse":10,"text":"큰 소리로 불러 가로되 거룩하고 참되신 대주재여 땅에 거하는 자들을 심판하여 우리 피를 신원하여 주지 아니하시기를 어느 때까지 하시려나이까 하니"},{"book":"요한계시록","chapter":6,"verse":11,"text":"각각 저희에게 흰 두루마기를 주시며 가라사대 아직 잠시 동안 쉬되 저희 동무 종들과 형제들도 자기처럼 죽임을 받아 그 수가 차기까지 하라 하시더라"},{"book":"요한계시록","chapter":6,"verse":12,"text":"내가 보니 여섯째 인을 떼실 때에 큰 지진이 나며 해가 총담 같이 검어지고 온 달이 피 같이 되며"},{"book":"요한계시록","chapter":6,"verse":13,"text":"하늘의 별들이 무화과나무가 대풍에 흔들려 선 과실이 떨어지는것 같이 땅에 떨어지며"},{"book":"요한계시록","chapter":6,"verse":14,"text":"하늘은 종이 축이 말리는것 같이 떠나가고 각 산과 섬이 제 자리에서 옮기우매"},{"book":"요한계시록","chapter":6,"verse":15,"text":"땅의 임금들과 왕족들과 장군들과 부자들과 강한 자들과 각 종과 자주자가 굴과 산 바위틈에 숨어"},{"book":"요한계시록","chapter":6,"verse":16,"text":"산과 바위에게 이르되 우리 위에 떨어져 보좌에 앉으신 이의 낯에서와 어린 양의 진노에서 우리를 가리우라"},{"book":"요한계시록","chapter":6,"verse":17,"text":"그들의 진노의 큰 날이 이르렀으니 누가 능히 서리요 하더라"},{"book":"요한계시록","chapter":7,"verse":1,"text":"이 일 후에 내가 네 천사가 땅 네 모퉁이에 선 것을 보니 땅의 사방의 바람을 붙잡아 바람으로 하여금 땅에나 바다에나 각종 나무에 불지 못하게 하더라"},{"book":"요한계시록","chapter":7,"verse":2,"text":"또 보매 다른 천사가 살아계신 하나님의 인을 가지고 해 돋는 데로부터 올라와서 땅과 바다를 해롭게 할 권세를 얻은 네 천사를 향하여 큰 소리로 외쳐"},{"book":"요한계시록","chapter":7,"verse":3,"text":"가로되 우리가 우리 하나님의 종들의 이마에 인치기까지 땅이나 바다나 나무나 해하지 말라 하더라"},{"book":"요한계시록","chapter":7,"verse":4,"text":"내가 인맞은 자의 수를 들으니 이스라엘 자손의 각 지파 중에서 인맞은 자들이 십 사만 사천이니"},{"book":"요한계시록","chapter":7,"verse":5,"text":"유다 지파 중에 인맞은 자가 일만 이천이요 르우벤 지파 중에 일만 이천이요 갓 지파 중에 일만 이천이요"},{"book":"요한계시록","chapter":7,"verse":6,"text":"아셀 지파 중에 일만 이천이요 납달리 지파 중에 일만 이천이요 므낫세 지파 중에 일만 이천이요"},{"book":"요한계시록","chapter":7,"verse":7,"text":"시므온 지파 중에 일만 이천이요 레위 지파 중에 일만 이천이요 잇사갈 지파 중에 일만 이천이요"},{"book":"요한계시록","chapter":7,"verse":8,"text":"스불론 지파 중에 일만 이천이요 요셉 지파 중에 일만 이천이요 베냐민 지파 중에 인맞은 자가 일만 이천이라"},{"book":"요한계시록","chapter":7,"verse":9,"text":"이 일 후에 내가 보니 각 나라와 족속과 백성과 방언에서 아무라도 능히 셀 수 없는 큰 무리가 흰 옷을 입고 손에 종려 가지를 들고 보좌 앞과 어린 양 앞에 서서"},{"book":"요한계시록","chapter":7,"verse":10,"text":"큰 소리로 외쳐 가로되 구원하심이 보좌에 앉으신 우리 하나님과 어린 양에게 있도다 하니"},{"book":"요한계시록","chapter":7,"verse":11,"text":"모든 천사가 보좌와 장로들과 네 생물의 주위에 섰다가 보좌 앞에 엎드려 얼굴을 대고 하나님께 경배하여"},{"book":"요한계시록","chapter":7,"verse":12,"text":"가로되 아멘 찬송과 영광과 지혜와 감사와 존귀와 능력과 힘이 우리 하나님께 세세토록 있을찌로다 아멘 하더라"},{"book":"요한계시록","chapter":7,"verse":13,"text":"장로 중에 하나가 응답하여 내게 이르되 이 흰옷 입은 자들이 누구며 또 어디서 왔느뇨"},{"book":"요한계시록","chapter":7,"verse":14,"text":"내가 가로되 내 주여 당신이 알리이다 하니 그가 나더러 이르되 이는 큰 환난에서 나오는 자들인데 어린양의 피에 그 옷을 씻어 희게 하였느니라"},{"book":"요한계시록","chapter":7,"verse":15,"text":"그러므로 그들이 하나님의 보좌 앞에 있고 또 그의 성전에서 밤낮 하나님을 섬기매 보좌에 앉으신 이가 그들 위에 장막을 치시리니"},{"book":"요한계시록","chapter":7,"verse":16,"text":"저희가 다시 주리지도 아니하며 목마르지도 아니하고 해나 아무 뜨거운 기운에 상하지 아니할찌니"},{"book":"요한계시록","chapter":7,"verse":17,"text":"이는 보좌 가운데 계신 어린 양이 저희의 목자가 되사 생명수 샘으로 인도하시고 하나님께서 저희 눈에서 모든 눈물을 씻어 주실 것임이러라"},{"book":"요한계시록","chapter":8,"verse":1,"text":"일곱째 인을 떼실 때에 하늘이 반시 동안쯤 고요하더니"},{"book":"요한계시록","chapter":8,"verse":2,"text":"내가 보매 하나님 앞에 시위한 일곱 천사가 있어 일곱 나팔을 받았더라"},{"book":"요한계시록","chapter":8,"verse":3,"text":"또 다른 천사가 와서 제단 곁에 서서 금 향로를 가지고 많은 향을 받았으니 이는 모든 성도의 기도들과 합하여 보좌 앞 금단에 드리고자 함이라"},{"book":"요한계시록","chapter":8,"verse":4,"text":"향연이 성도의 기도와 함께 천사의 손으로부터 하나님 앞으로 올라가는지라"},{"book":"요한계시록","chapter":8,"verse":5,"text":"천사가 향로를 가지고 단 위의 불을 담아다가 땅에 쏟으매 뇌성과 음성과 번개와 지진이 나더라"},{"book":"요한계시록","chapter":8,"verse":6,"text":"일곱 나팔 가진 일곱 천사가 나팔 불기를 예비하더라"},{"book":"요한계시록","chapter":8,"verse":7,"text":"첫째 천사가 나팔을 부니 피 섞인 우박과 불이 나서 땅에 쏟아지매 땅의 삼분의 일이 타서 사위고 수목의 삼분의 일도 타서 사위고 각종 푸른 풀도 타서 사위더라"},{"book":"요한계시록","chapter":8,"verse":8,"text":"둘째 천사가 나팔을 부니 불붙는 큰 산과 같은 것이 바다에 던지우매 바다의 삼분의 일이 피가 되고"},{"book":"요한계시록","chapter":8,"verse":9,"text":"바다 가운데 생명 가진 피조물들의 삼분의 일이 죽고 배들의 삼분의 일이 깨어지더라"},{"book":"요한계시록","chapter":8,"verse":10,"text":"세째 천사가 나팔을 부니 횃불 같이 타는 큰 별이 하늘에서 떨어져 강들의 삼분의 일과 여러 물샘에 떨어지니"},{"book":"요한계시록","chapter":8,"verse":11,"text":"이 별 이름은 쑥이라 물들의 삼분의 일이 쑥이 되매 그 물들이 쓰게 됨을 인하여 많은 사람이 죽더라"},{"book":"요한계시록","chapter":8,"verse":12,"text":"네째 천사가 나팔을 부니 해 삼분의 일과 달 삼분의 일과 별들의 삼분의 일이 침을 받아 그 삼분의 일이 어두워지니 낮 삼분의 일은 비췸이 없고 밤도 그러하더라"},{"book":"요한계시록","chapter":8,"verse":13,"text":"내가 또 보고 들으니 공중에 날아가는 독수리가 큰 소리로 이르되 땅에 거하는 자들에게 화, 화, 화가 있으리로다 이 외에도 세 천사의 불 나팔소리를 인함이로다 하더라"},{"book":"요한계시록","chapter":9,"verse":1,"text":"다섯째 천사가 나팔을 불매 내가 보니 하늘에서 땅에 떨어진 별 하나가 있는데 저가 무저갱의 열쇠를 받았더라"},{"book":"요한계시록","chapter":9,"verse":2,"text":"저가 무저갱을 여니 그 구멍에서 큰 풀무의 연기 같은 연기가 올라오매 해와 공기가 그 구멍의 연기로 인하여 어두워지며"},{"book":"요한계시록","chapter":9,"verse":3,"text":"또 황충이 연기 가운데로부터 땅 위에 나오매 저희가 땅에 있는 전갈의 권세와 같은 권세를 받았더라"},{"book":"요한계시록","chapter":9,"verse":4,"text":"저희에게 이르시되 땅의 풀이나 푸른 것이나 각종 수목은 해하지 말고 오직 이마에 하나님의 인 맞지 아니한 사람들만 해하라 하시더라"},{"book":"요한계시록","chapter":9,"verse":5,"text":"그러나 그들을 죽이지는 못하게 하시고 다섯달 동안 괴롭게만 하게 하시는데 그 괴롭게 함은 전갈이 사람을 쏠 때에 괴롭게 함과 같더라"},{"book":"요한계시록","chapter":9,"verse":6,"text":"그날에는 사람들이 죽기를 구하여도 얻지 못하고 죽고 싶으나 죽음이 저희를 피하리로다"},{"book":"요한계시록","chapter":9,"verse":7,"text":"황충들의 모양은 전쟁을 위하여 예비한 말들 같고 그 머리에 금 같은 면류관 비슷한 것을 썼으며 그 얼굴은 사람의 얼굴 같고"},{"book":"요한계시록","chapter":9,"verse":8,"text":"또 여자의 머리털 같은 머리털이 있고 그 이는 사자의 이 같으며"},{"book":"요한계시록","chapter":9,"verse":9,"text":"또 철흉갑 같은 흉갑이 있고 그 날개들의 소리는 병거와 많은 말들이 전장으로 달려 들어가는 소리 같으며"},{"book":"요한계시록","chapter":9,"verse":10,"text":"또 전갈과 같은 꼬리와 쏘는 살이 있어 그 꼬리에는 다섯달 동안 사람들을 해하는 권세가 있더라"},{"book":"요한계시록","chapter":9,"verse":11,"text":"저희에게 임금이 있으니 무저갱의 사자라 히브리 음으로 이름은 아바돈이요 헬라 음으로 이름은 아볼루온이더라"},{"book":"요한계시록","chapter":9,"verse":12,"text":"첫째 화는 지나갔으나 보라 아직도 이 후에 화 둘이 이르리로다"},{"book":"요한계시록","chapter":9,"verse":13,"text":"여섯째 천사가 나팔을 불매 내가 들으니 하나님 앞 금단 네 뿔에서 한 음성이 나서"},{"book":"요한계시록","chapter":9,"verse":14,"text":"나팔 가진 여섯째 천사에게 말하기를 큰 강 유브라데에 결박한 네 천사를 놓아 주라 하매"},{"book":"요한계시록","chapter":9,"verse":15,"text":"네 천사가 놓였으니 그들은 그 년 월 일 시에 이르러 사람 삼분의 일을 죽이기로 예비한 자들이더라"},{"book":"요한계시록","chapter":9,"verse":16,"text":"마병대의 수는 이만만이니 내가 그들의 수를 들었노라"},{"book":"요한계시록","chapter":9,"verse":17,"text":"이같이 이상한 가운데 그 말들과 그 탄 자들을 보니 불빛과 자주빛과 유황빛 흉갑이 있고 또 말들의 머리는 사자 머리 같고 그 입에서는 불과 연기와 유황이 나오더라"},{"book":"요한계시록","chapter":9,"verse":18,"text":"이 세 재앙 곧 저희 입에서 나오는 불과 연기와 유황을 인하여 사람 삼분의 일이 죽임을 당하니라"},{"book":"요한계시록","chapter":9,"verse":19,"text":"이 말들의 힘은 그 입과 그 꼬리에 있으니 그 꼬리는 뱀 같고 또 꼬리에 머리가 있어 이것으로 해하더라"},{"book":"요한계시록","chapter":9,"verse":20,"text":"이 재앙에 죽지 않고 남은 사람들은 그 손으로 행하는 일을 회개치 아니하고 오히려 여러 귀신과 또는 보거나 듣거나 다니거나 하지 못하는 금, 은, 동과 목석의 우상에게 절하고"},{"book":"요한계시록","chapter":9,"verse":21,"text":"또 그 살인과 복술과 음행과 도적질을 회개치 아니하더라"},{"book":"요한계시록","chapter":10,"verse":1,"text":"내가 또 보니 힘센 다른 천사가 구름을 입고 하늘에서 내려 오는데 그 머리 위에 무지개가 있고 그 얼굴은 해 같고 그 발은 불기둥 같으며"},{"book":"요한계시록","chapter":10,"verse":2,"text":"그 손에 펴 놓인 작은 책을 들고 그 오른발은 바다를 밟고 왼발은 땅을 밟고"},{"book":"요한계시록","chapter":10,"verse":3,"text":"사자의 부르짖는것 같이 큰 소리로 외치니 외칠 때에 일곱 우뢰가 그 소리를 발하더라"},{"book":"요한계시록","chapter":10,"verse":4,"text":"일곱 우뢰가 발할 때에 내가 기록하려고 하다가 곧 들으니 하늘에서 소리나서 말하기를 일곱 우뢰가 발한 것을 인봉하고 기록하지 말라 하더라"},{"book":"요한계시록","chapter":10,"verse":5,"text":"내가 본바 바다와 땅을 밟고 섰는 천사가 하늘을 향하여 오른손을 들고"},{"book":"요한계시록","chapter":10,"verse":6,"text":"세세토록 살아계신 자 곧 하늘과 그 가운데 있는 물건이며 땅과 그 가운데 있는 물건이며 바다와 그 가운데 있는 물건을 창조하신 이를 가리켜 맹세하여 가로되 지체하지 아니하리니"},{"book":"요한계시록","chapter":10,"verse":7,"text":"일곱째 천사가 소리 내는 날 그 나팔을 불게 될 때에 하나님의 비밀이 그 종 선지자들에게 전하신 복음과 같이 이루리라"},{"book":"요한계시록","chapter":10,"verse":8,"text":"하늘에서 나서 내게 들리던 음성이 또 내게 말하여 가로되 네가 가서 바다와 땅을 밟고 섰는 천사의 손에 펴 놓인 책을 가지라 하기로"},{"book":"요한계시록","chapter":10,"verse":9,"text":"내가 천사에게 나아가 작은 책을 달라 한즉 천사가 가로되 갖다 먹어버리라 네 배에는 쓰나 네 입에는 꿀 같이 달리라 하거늘"},{"book":"요한계시록","chapter":10,"verse":10,"text":"내가 천사의 손에서 작은 책을 갖다 먹어버리니 내 입에는 꿀 같이 다나 먹은 후에 내 배에서는 쓰게 되더라"},{"book":"요한계시록","chapter":10,"verse":11,"text":"저가 내게 말하기를 네가 많은 백성과 나라와 방언과 임금에게 다시 예언하여야 하리라 하더라"},{"book":"요한계시록","chapter":11,"verse":1,"text":"또 내게 지팡이 같은 갈대를 주며 말하기를 일어나서 하나님의 성전과 제단과 그 안에서 경배하는 자들을 척량하되"},{"book":"요한계시록","chapter":11,"verse":2,"text":"성전 밖 마당은 척량하지 말고 그냥 두라 이것을 이방인에게 주었은즉 저희가 거룩한 성을 마흔 두달 동안 짓밟으리라"},{"book":"요한계시록","chapter":11,"verse":3,"text":"내가 나의 두 증인에게 권세를 주리니 저희가 굵은 베옷을 입고 일천 이백 육십 일을 예언하리라"},{"book":"요한계시록","chapter":11,"verse":4,"text":"이는 이 땅의 주 앞에 섰는 두 감람나무와 두 촛대니"},{"book":"요한계시록","chapter":11,"verse":5,"text":"만일 누구든지 저희를 해하고자 한즉 저희 입에서 불이 나서 그 원수를 소멸할찌니 누구든지 해하려 하면 반드시 이와 같이 죽임을 당하리라"},{"book":"요한계시록","chapter":11,"verse":6,"text":"저희가 권세를 가지고 하늘을 닫아 그 예언을 하는 날 동안 비 오지 못하게 하고 또 권세를 가지고 물을 변하여 피 되게 하고 아무 때든지 원하는 대로 여러가지 재앙으로 땅을 치리로다"},{"book":"요한계시록","chapter":11,"verse":7,"text":"저희가 그 증거를 마칠 때에 무저갱으로부터 올라오는 짐승이 저희로 더불어 전쟁을 일으켜 저희를 이기고 저희를 죽일터인즉"},{"book":"요한계시록","chapter":11,"verse":8,"text":"저희 시체가 큰 성길에 있으리니 그 성은 영적으로 하면 소돔이라고도 하고 애굽이라고도 하니 곧 저희 주께서 십자가에 못 박히신 곳이니라"},{"book":"요한계시록","chapter":11,"verse":9,"text":"백성들과 족속과 방언과 나라 중에서 사람들이 그 시체를 사흘 반 동안을 목도하며 무덤에 장사하지 못하게 하리로다"},{"book":"요한계시록","chapter":11,"verse":10,"text":"이 두 선지자가 땅에 거하는 자들을 괴롭게 한고로 땅에 거하는 자들이 저희의 죽음을 즐거워하고 기뻐하여 서로 예물을 보내리라 하더라"},{"book":"요한계시록","chapter":11,"verse":11,"text":"삼일 반 후에 하나님께로부터 생기가 저희 속에 들어가매 저희가 발로 일어서니 구경하는 자들이 크게 두려워하더라"},{"book":"요한계시록","chapter":11,"verse":12,"text":"하늘로부터 큰 음성이 있어 이리로 올라오라 함을 저희가 듣고 구름을 타고 하늘로 올라가니 저희 원수들도 구경하더라"},{"book":"요한계시록","chapter":11,"verse":13,"text":"그 시에 큰 지진이 나서 성 십분의 일이 무너지고 지진에 죽은 사람이 칠천이라 그 남은 자들이 두려워하여 영광을 하늘의 하나님께 돌리더라"},{"book":"요한계시록","chapter":11,"verse":14,"text":"둘째 화는 지나갔으나 보라 세째 화가 속히 이르는도다"},{"book":"요한계시록","chapter":11,"verse":15,"text":"일곱째 천사가 나팔을 불매 하늘에 큰 음성들이 나서 가로되 세상 나라가 우리 주와 그 그리스도의 나라가 되어 그가 세세토록 왕노릇 하시리로다 하니"},{"book":"요한계시록","chapter":11,"verse":16,"text":"하나님 앞에 자기 보좌에 앉은 이십 사 장로들이 엎드려 얼굴을 대고 하나님께 경배하여"},{"book":"요한계시록","chapter":11,"verse":17,"text":"가로되 감사하옵나니 옛적에도 계셨고 시방도 계신 주 하나님 곧 전능하신이여 친히 큰 권능을 잡으시고 왕노릇 하시도다"},{"book":"요한계시록","chapter":11,"verse":18,"text":"이방들이 분노하매 주의 진노가 임하여 죽은 자를 심판하시며 종 선지자들과 성도들과 또 무론대소하고 주의 이름을 경외하는 자들에게 상 주시며 또 땅을 망하게 하는 자들을 멸망시키실 때로소이다 하더라"},{"book":"요한계시록","chapter":11,"verse":19,"text":"이에 하늘에 있는 하나님의 성전이 열리니 성전 안에 하나님의 언약궤가 보이며 또 번개와 음성들과 뇌성과 지진과 큰 우박이 있더라"},{"book":"요한계시록","chapter":12,"verse":1,"text":"하늘에 큰 이적이 보이니 해를 입은 한 여자가 있는데 그 발 아래는 달이 있고 그 머리에는 열 두 별의 면류관을 썼더라"},{"book":"요한계시록","chapter":12,"verse":2,"text":"이 여자가 아이를 배어 해산하게 되매 아파서 애써 부르짖더라"},{"book":"요한계시록","chapter":12,"verse":3,"text":"하늘에 또 다른 이적이 보이니 보라 한 큰 붉은 용이 있어 머리가 일곱이요 뿔이 열이라 그 여러 머리에 일곱 면류관이 있는데"},{"book":"요한계시록","chapter":12,"verse":4,"text":"그 꼬리가 하늘 별 삼분의 일을 끌어다가 땅에 던지더라 용이 해산하려는 여자 앞에서 그가 해산하면 그 아이를 삼키고자 하더니"},{"book":"요한계시록","chapter":12,"verse":5,"text":"여자가 아들을 낳으니 이는 장차 철장으로 만국을 다스릴 남자라 그 아이를 하나님 앞과 그 보좌 앞으로 올려가더라"},{"book":"요한계시록","chapter":12,"verse":6,"text":"그 여자가 광야로 도망하매 거기서 일천 이백 육십일 동안 저를 양육하기 위하여 하나님의 예비하신 곳이 있더라"},{"book":"요한계시록","chapter":12,"verse":7,"text":"하늘에 전쟁이 있으니 미가엘과 그의 사자들이 용으로 더불어 싸울쌔 용과 그의 사자들도 싸우나"},{"book":"요한계시록","chapter":12,"verse":8,"text":"이기지 못하여 다시 하늘에서 저희의 있을 곳을 얻지 못한지라"},{"book":"요한계시록","chapter":12,"verse":9,"text":"큰 용이 내어 쫓기니 옛 뱀 곧 마귀라고도 하고 사단이라고도 하는 온 천하를 꾀는 자라 땅으로 내어 쫓기니 그의 사자들도 저와 함께 내어 쫓기니라"},{"book":"요한계시록","chapter":12,"verse":10,"text":"내가 또 들으니 하늘에 큰 음성이 있어 가로되 이제 우리 하나님의 구원과 능력과 나라와 또 그의 그리스도의 권세가 이루었으니 우리 형제들을 참소하던 자 곧 우리 하나님 앞에서 밤낮 참소하던 자가 쫓겨 났고"},{"book":"요한계시록","chapter":12,"verse":11,"text":"또 여러 형제가 어린 양의 피와 자기의 증거하는 말을 인하여 저를 이기었으니 그들은 죽기까지 자기 생명을 아끼지 아니하였도다"},{"book":"요한계시록","chapter":12,"verse":12,"text":"그러므로 하늘과 그 가운데 거하는 자들은 즐거워하라 그러나 땅과 바다는 화 있을찐저 이는 마귀가 자기의 때가 얼마 못된 줄을 알므로 크게 분내어 너희에게 내려 갔음이라 하더라"},{"book":"요한계시록","chapter":12,"verse":13,"text":"용이 자기가 땅으로 내어쫓긴 것을 보고 남자를 낳은 여자를 핍박하는지라"},{"book":"요한계시록","chapter":12,"verse":14,"text":"그 여자가 큰 독수리의 두 날개를 받아 광야 자기 곳으로 날아가 거기서 그 뱀의 낯을 피하여 한 때와 두 때와 반 때를 양육 받으매"},{"book":"요한계시록","chapter":12,"verse":15,"text":"여자의 뒤에서 뱀이 그 입으로 물을 강 같이 토하여 여자를 물에 떠내려 가게 하려 하되"},{"book":"요한계시록","chapter":12,"verse":16,"text":"땅이 여자를 도와 그 입을 벌려 용의 입에서 토한 강물을 삼키니"},{"book":"요한계시록","chapter":12,"verse":17,"text":"용이 여자에게 분노하여 돌아가서 그 여자의 남은 자손 곧 하나님의 계명을 지키며 예수의 증거를 가진 자들로 더불어 싸우려고 바다 모래 위에 섰더라"},{"book":"요한계시록","chapter":13,"verse":1,"text":"내가 보니 바다에서 한 짐승이 나오는데 뿔이 열이요 머리가 일곱이라 그 뿔에는 열 면류관이 있고 그 머리들에는 참람된 이름들이 있더라"},{"book":"요한계시록","chapter":13,"verse":2,"text":"내가 본 짐승은 표범과 비슷하고 그 발은 곰의 발 같고 그 입은 사자의 입 같은데 용이 자기의 능력과 보좌와 큰 권세를 그에게 주었더라"},{"book":"요한계시록","chapter":13,"verse":3,"text":"그의 머리 하나가 상하여 죽게 된 것 같더니 그 죽게 되었던 상처가 나으매 온 땅이 이상히 여겨 짐승을 따르고"},{"book":"요한계시록","chapter":13,"verse":4,"text":"용이 짐승에게 권세를 주므로 용에게 경배하며 짐승에게 경배하여 가로되 누가 이 짐승과 같으뇨 누가 능히 이로 더불어 싸우리요 하더라"},{"book":"요한계시록","chapter":13,"verse":5,"text":"또 짐승이 큰 말과 참람된 말 하는 입을 받고 또 마흔 두달 일할 권세를 받으니라"},{"book":"요한계시록","chapter":13,"verse":6,"text":"짐승이 입을 벌려 하나님을 향하여 훼방하되 그의 이름과 그의 장막 곧 하늘에 거하는 자들을 훼방하더라"},{"book":"요한계시록","chapter":13,"verse":7,"text":"또 권세를 받아 성도들과 싸워 이기게 되고 각 족속과 백성과 방언과 나라를 다스리는 권세를 받으니"},{"book":"요한계시록","chapter":13,"verse":8,"text":"죽임을 당한 어린 양의 생명책에 창세 이후로 녹명되지 못하고 이 땅에 사는 자들은 다 짐승에게 경배하리라"},{"book":"요한계시록","chapter":13,"verse":9,"text":"누구든지 귀가 있거든 들을찌어다"},{"book":"요한계시록","chapter":13,"verse":10,"text":"사로잡는 자는 사로잡힐 것이요 칼로 죽이는 자는 자기도 마땅히 칼에 죽으리니 성도들의 인내와 믿음이 여기 있느니라"},{"book":"요한계시록","chapter":13,"verse":11,"text":"내가 보매 또 다른 짐승이 땅에서 올라오니 새끼양 같이 두 뿔이 있고 용처럼 말하더라"},{"book":"요한계시록","chapter":13,"verse":12,"text":"저가 먼저 나온 짐승의 모든 권세를 그 앞에서 행하고 땅과 땅에 거하는 자들로 처음 짐승에게 경배하게 하니 곧 죽게 되었던 상처가 나은 자니라"},{"book":"요한계시록","chapter":13,"verse":13,"text":"큰 이적을 행하되 심지어 사람들 앞에서 불이 하늘로부터 땅에 내려 오게 하고"},{"book":"요한계시록","chapter":13,"verse":14,"text":"짐승 앞에서 받은바 이적을 행함으로 땅에 거하는 자들을 미혹하며 땅에 거하는 자들에게 이르기를 칼에 상하였다가 살아난 짐승을 위하여 우상을 만들라 하더라"},{"book":"요한계시록","chapter":13,"verse":15,"text":"저가 권세를 받아 그 짐승의 우상에게 생기를 주어 그 짐승의 우상으로 말하게 하고 또 짐승의 우상에게 경배하지 아니하는 자는 몇이든지 다 죽이게 하더라"},{"book":"요한계시록","chapter":13,"verse":16,"text":"저가 모든 자 곧 작은 자나 큰 자나 부자나 빈궁한 자나 자유한 자나 종들로 그 오른손에나 이마에 표를 받게 하고"},{"book":"요한계시록","chapter":13,"verse":17,"text":"누구든지 이 표를 가진 자 외에는 매매를 못하게 하니 이 표는 곧 짐승의 이름이나 그 이름의 수라"},{"book":"요한계시록","chapter":13,"verse":18,"text":"지혜가 여기 있으니 총명 있는 자는 그 짐승의 수를 세어 보라 그 수는 사람의 수니 육백 육십 륙이니라"},{"book":"요한계시록","chapter":14,"verse":1,"text":"또 내가 보니 보라 어린 양이 시온산에 섰고 그와 함께 십 사만 사천이 섰는데 그 이마에 어린 양의 이름과 그 아버지의 이름을 쓴 것이 있도다"},{"book":"요한계시록","chapter":14,"verse":2,"text":"내가 하늘에서 나는 소리를 들으니 많은 물소리도 같고 큰 뇌성도 같은데 내게 들리는 소리는 거문고 타는 자들의 그 거문고 타는 것 같더라"},{"book":"요한계시록","chapter":14,"verse":3,"text":"저희가 보좌와 네 생물과 장로들 앞에서 새 노래를 부르니 땅에서 구속함을 얻은 십 사만 사천인 밖에는 능히 이 노래를 배울 자가 없더라"},{"book":"요한계시록","chapter":14,"verse":4,"text":"이 사람들은 여자로 더불어 더럽히지 아니하고 정절이 있는 자라 어린 양이 어디로 인도하든지 따라가는 자며 사람 가운데서 구속을 받아 처음 익은 열매로 하나님과 어린 양에게 속한 자들이니"},{"book":"요한계시록","chapter":14,"verse":5,"text":"그 입에 거짓말이 없고 흠이 없는 자들이더라"},{"book":"요한계시록","chapter":14,"verse":6,"text":"또 보니 다른 천사가 공중에 날아가는데 땅에 거하는 자들 곧 여러 나라와 족속과 방언과 백성에게 전할 영원한 복음을 가졌더라"},{"book":"요한계시록","chapter":14,"verse":7,"text":"그가 큰 음성으로 가로되 하나님을 두려워하며 그에게 영광을 돌리라 이는 그의 심판하실 시간이 이르렀음이니 하늘과 땅과 바다와 물들의 근원을 만드신 이를 경배하라 하더라"},{"book":"요한계시록","chapter":14,"verse":8,"text":"또 다른 천사 곧 둘째가 그 뒤를 따라 말하되 무너졌도다 무너졌도다 큰 성 바벨론이여 모든 나라를 그 음행으로 인하여 진노의 포도주로 먹이던 자로다 하더라"},{"book":"요한계시록","chapter":14,"verse":9,"text":"또 다른 천사 곧 세째가 그 뒤를 따라 큰 음성으로 가로되 만일 누구든지 짐승과 그의 우상에게 경배하고 이마에나 손에 표를 받으면"},{"book":"요한계시록","chapter":14,"verse":10,"text":"그도 하나님의 진노의 포도주를 마시리니 그 진노의 잔에 섞인 것이 없이 부은 포도주라 거룩한 천사들 앞과 어린 양 앞에서 불과 유황으로 고난을 받으리니"},{"book":"요한계시록","chapter":14,"verse":11,"text":"그 고난의 연기가 세세토록 올라가리로다 짐승과 그의 우상에게 경배하고 그 이름의 표를 받는 자는 누구든지 밤낮 쉼을 얻지 못하리라 하더라"},{"book":"요한계시록","chapter":14,"verse":12,"text":"성도들의 인내가 여기 있나니 저희는 하나님의 계명과 예수 믿음을 지키는 자니라"},{"book":"요한계시록","chapter":14,"verse":13,"text":"또 내가 들으니 하늘에서 음성이 나서 가로되 기록하라 자금 이후로 주 안에서 죽는 자들은 복이 있도다 하시매 성령이 가라사대 그러하다 저희 수고를 그치고 쉬리니 이는 저희의 행한 일이 따름이라 하시더라"},{"book":"요한계시록","chapter":14,"verse":14,"text":"또 내가 보니 흰구름이 있고 구름 위에 사람의 아들과 같은 이가 앉았는데 그 머리에는 금 면류관이 있고 그 손에는 이한 낫을 가졌더라"},{"book":"요한계시록","chapter":14,"verse":15,"text":"또 다른 천사가 성전으로부터 나와 구름 위에 앉은이를 향하여 큰 음성으로 외쳐 가로되 네 낫을 휘둘러 거두라 거둘 때가 이르러 땅에 곡식이 다 익었음이로다 하니"},{"book":"요한계시록","chapter":14,"verse":16,"text":"구름 위에 앉으신 이가 낫을 땅에 휘두르매 곡식이 거두어지니라"},{"book":"요한계시록","chapter":14,"verse":17,"text":"또 다른 천사가 하늘에 있는 성전에서 나오는데 또한 이한 낫을 가졌더라"},{"book":"요한계시록","chapter":14,"verse":18,"text":"또 불을 다스리는 다른 천사가 제단으로부터 나와 이한 낫 가진 자를 향하여 큰 음성으로 불러 가로되 네 이한 낫을 휘둘러 땅의 포도송이를 거두라 그 포도가 익었느니라 하더라"},{"book":"요한계시록","chapter":14,"verse":19,"text":"천사가 낫을 땅에 휘둘러 땅의 포도를 거두어 하나님의 진노의 큰 포도주 틀에 던지매"},{"book":"요한계시록","chapter":14,"verse":20,"text":"성 밖에서 그 틀이 밟히니 틀에서 피가 나서 말굴레까지 닿았고 일천 육백 스다디온에 퍼졌더라"},{"book":"요한계시록","chapter":15,"verse":1,"text":"또 하늘에 크고 이상한 다른 이적을 보매 일곱 천사가 일곱 재앙을 가졌으니 곧 마지막 재앙이라 하나님의 진노가 이것으로 마치리로다"},{"book":"요한계시록","chapter":15,"verse":2,"text":"또 내가 보니 불이 섞인 유리 바다 같은 것이 있고 짐승과 그의 우상과 그의 이름의 수를 이기고 벗어난 자들이 유리바다 가에 서서 하나님의 거문고를 가지고"},{"book":"요한계시록","chapter":15,"verse":3,"text":"하나님의 종 모세의 노래, 어린 양의 노래를 불러 가로되 주 하나님 곧 전능하신이시여 하시는 일이 크고 기이하시도다 만국의 왕이시여 주의 길이 의롭고 참되시도다"},{"book":"요한계시록","chapter":15,"verse":4,"text":"주여 누가 주의 이름을 두려워하지 아니하며 영화롭게 하지 아니하오리이까 오직 주만 거룩하시니이다 주의 의로우신 일이 나타났으매 만국이 와서 주께 경배하리이다 하더라"},{"book":"요한계시록","chapter":15,"verse":5,"text":"또 이 일 후에 내가 보니 하늘에 증거 장막의 성전이 열리며"},{"book":"요한계시록","chapter":15,"verse":6,"text":"일곱 재앙을 가진 일곱 천사가 성전으로부터 나와 맑고 빛난 세마포 옷을 입고 가슴에 금띠를 띠고"},{"book":"요한계시록","chapter":15,"verse":7,"text":"네 생물 중에 하나가 세세에 계신 하나님의 진노를 가득히 담은 금대접 일곱을 그 일곱 천사에게 주니"},{"book":"요한계시록","chapter":15,"verse":8,"text":"하나님의 영광과 능력을 인하여 성전에 연기가 차게 되매 일곱 천사의 일곱 재앙이 마치기까지는 성전에 능히 들어갈 자가 없더라"},{"book":"요한계시록","chapter":16,"verse":1,"text":"또 내가 들으니 성전에서 큰 음성이 나서 일곱 천사에게 말하되 너희는 가서 하나님의 진노의 일곱 대접을 땅에 쏟으라 하더라"},{"book":"요한계시록","chapter":16,"verse":2,"text":"첫째가 가서 그 대접을 땅에 쏟으매 악하고 독한 헌데가 짐승의 표를 받은 사람들과 그 우상에게 경배하는 자들에게 나더라"},{"book":"요한계시록","chapter":16,"verse":3,"text":"둘째가 그 대접을 바다에 쏟으매 바다가 곧 죽은 자의 피 같이 되니 바다 가운데 모든 생물이 죽더라"},{"book":"요한계시록","chapter":16,"verse":4,"text":"세째가 그 대접을 강과 물 근원에 쏟으매 피가 되더라"},{"book":"요한계시록","chapter":16,"verse":5,"text":"내가 들으니 물을 차지한 천사가 가로되 전에도 계셨고 시방도 계신 거룩하신 이여 이렇게 심판하시니 의로우시도다"},{"book":"요한계시록","chapter":16,"verse":6,"text":"저희가 성도들과 선지자들의 피를 흘렸으므로 저희로 피를 마시게 하신 것이 합당하니이다 하더라"},{"book":"요한계시록","chapter":16,"verse":7,"text":"또 내가 들으니 제단이 말하기를 그러하다 주 하나님 곧 전능하신 이시여 심판하시는 것이 참되시고 의로우시도다 하더라"},{"book":"요한계시록","chapter":16,"verse":8,"text":"네째가 그 대접을 해에 쏟으매 해가 권세를 받아 불로 사람들을 태우니"},{"book":"요한계시록","chapter":16,"verse":9,"text":"사람들이 크게 태움에 태워진지라 이 재앙들을 행하는 권세를 가지신 하나님의 이름을 훼방하며 또 회개하여 영광을 주께 돌리지 아니하더라"},{"book":"요한계시록","chapter":16,"verse":10,"text":"또 다섯째가 그 대접을 짐승의 보좌에 쏟으니 그 나라가 곧 어두워지며 사람들이 아파서 자기 혀를 깨물고"},{"book":"요한계시록","chapter":16,"verse":11,"text":"아픈 것과 종기로 인하여 하늘의 하나님을 훼방하고 저희 행위를 회개치 아니하더라"},{"book":"요한계시록","chapter":16,"verse":12,"text":"또 여섯째가 그 대접을 큰 강 유브라데에 쏟으매 강물이 말라서 동방에서 오는 왕들의 길이 예비되더라"},{"book":"요한계시록","chapter":16,"verse":13,"text":"또 내가 보매 개구리 같은 세 더러운 영이 용의 입과 짐승의 입과 거짓 선지자의 입에서 나오니"},{"book":"요한계시록","chapter":16,"verse":14,"text":"저희는 귀신의 영이라 이적을 행하여 온 천하 임금들에게 가서 하나님 곧 전능하신이의 큰 날에 전쟁을 위하여 그들을 모으더라"},{"book":"요한계시록","chapter":16,"verse":15,"text":"보라 내가 도적 같이 오리니 누구든지 깨어 자기 옷을 지켜 벌거벗고 다니지 아니하며 자기의 부끄러움을 보이지 아니하는 자가 복이 있도다"},{"book":"요한계시록","chapter":16,"verse":16,"text":"세 영이 히브리 음으로 아마겟돈이라 하는 곳으로 왕들을 모으더라"},{"book":"요한계시록","chapter":16,"verse":17,"text":"일곱째가 그 대접을 공기 가운데 쏟으매 큰 음성이 성전에서 보좌로부터 나서 가로되 되었다 하니"},{"book":"요한계시록","chapter":16,"verse":18,"text":"번개와 음성들과 뇌성이 있고 또 큰 지진이 있어 어찌 큰지 사람이 땅에 있어 옴으로 이같이 큰 지진이 없었더라"},{"book":"요한계시록","chapter":16,"verse":19,"text":"큰 성이 세 갈래로 갈라지고 만국의 성들도 무너지니 큰 성 바벨론이 하나님 앞에 기억하신바 되어 그의 맹렬한 진노의 포도주 잔을 받으매"},{"book":"요한계시록","chapter":16,"verse":20,"text":"각 섬도 없어지고 산악도 간데 없더라"},{"book":"요한계시록","chapter":16,"verse":21,"text":"또 중수가 한 달란트나 되는 큰 우박이 하늘로부터 사람들에게 내리매 사람들이 그 박재로 인하여 하나님을 훼방하니 그 재앙이 심히 큼이러라"},{"book":"요한계시록","chapter":17,"verse":1,"text":"또 일곱 대접을 가진 일곱 천사 중 하나가 와서 내게 말하여 가로되 이리 오라 많은 물위에 앉은 큰 음녀의 받을 심판을 네게 보이리라"},{"book":"요한계시록","chapter":17,"verse":2,"text":"땅의 임금들도 그로 더불어 음행하였고 땅에 거하는 자들도 그 음행의 포도주에 취하였다 하고"},{"book":"요한계시록","chapter":17,"verse":3,"text":"곧 성령으로 나를 데리고 광야로 가니라 내가 보니 여자가 붉은 빛 짐승을 탔는데 그 짐승의 몸에 참람된 이름들이 가득하고 일곱 머리와 열 뿔이 있으며"},{"book":"요한계시록","chapter":17,"verse":4,"text":"그 여자는 자주 빛과 붉은 빛 옷을 입고 금과 보석과 진주로 꾸미고 손에 금잔을 가졌는데 가증한 물건과 그의 음행의 더러운 것들이 가득하더라"},{"book":"요한계시록","chapter":17,"verse":5,"text":"그 이마에 이름이 기록되었으니 비밀이라, 큰 바벨론이라, 땅의 음녀들과 가증한 것들의 어미라 하였더라"},{"book":"요한계시록","chapter":17,"verse":6,"text":"또 내가 보매 이 여자가 성도들의 피와 예수의 증인들의 피에 취한지라 내가 그 여자를 보고 기이히 여기고 크게 기이히 여기니"},{"book":"요한계시록","chapter":17,"verse":7,"text":"천사가 가로되 왜 기이히 여기느냐 내가 여자와 그의 탄바 일곱 머리와 열 뿔 가진 짐승의 비밀을 네게 이르리라"},{"book":"요한계시록","chapter":17,"verse":8,"text":"네가 본 짐승은 전에 있었다가 시방 없으나 장차 무저갱으로부터 올라와 멸망으로 들어갈 자니 땅에 거하는 자들로서 창세 이후로 생명책에 녹명되지 못한 자들이 이전에 있었다가 시방 없으나 장차 나올 짐승을 보고 기이히 여기리라"},{"book":"요한계시록","chapter":17,"verse":9,"text":"지혜 있는 뜻이 여기 있으니 그 일곱 머리는 여자가 앉은 일곱 산이요"},{"book":"요한계시록","chapter":17,"verse":10,"text":"또 일곱 왕이라 다섯은 망하였고 하나는 있고 다른이는 아직 이르지 아니하였으나 이르면 반드시 잠간 동안 계속하리라"},{"book":"요한계시록","chapter":17,"verse":11,"text":"전에 있었다가 시방 없어진 짐승은 여덟째 왕이니 일곱 중에 속한 자라 저가 멸망으로 들어가리라"},{"book":"요한계시록","chapter":17,"verse":12,"text":"네가 보던 열 뿔은 열 왕이니 아직 나라를 얻지 못하였으나 다만 짐승으로 더불어 임금처럼 권세를 일시 동안 받으리라"},{"book":"요한계시록","chapter":17,"verse":13,"text":"저희가 한 뜻을 가지고 자기의 능력과 권세를 짐승에게 주더라"},{"book":"요한계시록","chapter":17,"verse":14,"text":"저희가 어린 양으로 더불어 싸우려니와 어린 양은 만주의 주시요 만왕의 왕이시므로 저희를 이기실터이요 또 그와 함께 있는 자들 곧 부르심을 입고 빼내심을 얻고 진실한 자들은 이기리로다"},{"book":"요한계시록","chapter":17,"verse":15,"text":"또 천사가 내게 말하되 네가 본바 음녀의 앉은 물은 백성과 무리와 열국과 방언들이니라"},{"book":"요한계시록","chapter":17,"verse":16,"text":"네가 본바 이 열 뿔과 짐승이 음녀를 미워하여 망하게 하고 벌거벗게 하고 그 살을 먹고 불로 아주 사르리라"},{"book":"요한계시록","chapter":17,"verse":17,"text":"하나님이 자기 뜻대로 할 마음을 저희에게 주사 한 뜻을 이루게 하시고 저희 나라를 그 짐승에게 주게 하시되 하나님 말씀이 응하기까지 하심이니라"},{"book":"요한계시록","chapter":17,"verse":18,"text":"또 네가 본바 여자는 땅의 임금들을 다스리는 큰 성이라 하더라"},{"book":"요한계시록","chapter":18,"verse":1,"text":"이 일 후에 다른 천사가 하늘에서 내려오는 것을 보니 큰 권세를 가졌는데 그의 영광으로 땅이 환하여지더라"},{"book":"요한계시록","chapter":18,"verse":2,"text":"힘센 음성으로 외쳐 가로되 무너졌도다 무너졌도다 큰 성 바벨론이여 귀신의 처소와 각종 더러운 영의 모이는 곳과 각종 더럽고 가증한 새의 모이는 곳이 되었도다"},{"book":"요한계시록","chapter":18,"verse":3,"text":"그 음행의 진노의 포도주를 인하여 만국이 무너졌으며 또 땅의 왕들이 그로 더불어 음행하였으며 땅의 상고들도 그 사치의 세력을 인하여 치부하였도다 하더라"},{"book":"요한계시록","chapter":18,"verse":4,"text":"또 내가 들으니 하늘로서 다른 음성이 나서 가로되 내 백성아, 거기서 나와 그의 죄에 참예하지 말고 그의 받을 재앙들을 받지 말라"},{"book":"요한계시록","chapter":18,"verse":5,"text":"그 죄는 하늘에 사무쳤으며 하나님은 그의 불의한 일을 기억하신지라"},{"book":"요한계시록","chapter":18,"verse":6,"text":"그가 준 그대로 그에게 주고 그의 행위대로 갑절을 갚아주고 그의 섞은 잔에도 갑절이나 섞어 그에게 주라"},{"book":"요한계시록","chapter":18,"verse":7,"text":"그가 어떻게 자기를 영화롭게 하였으며 사치하였든지 그만큼 고난과 애통으로 갚아 주라 그가 마음에 말하기를 나는 여황으로 앉은 자요 과부가 아니라 결단코 애통을 당하지 아니하리라 하니"},{"book":"요한계시록","chapter":18,"verse":8,"text":"그러므로 하루 동안에 그 재앙들이 이르리니 곧 사망과 애통과 흉년이라 그가 또한 불에 살라지리니 그를 심판하신 주 하나님은 강하신 자이심이니라"},{"book":"요한계시록","chapter":18,"verse":9,"text":"그와 함께 음행하고 사치하던 땅의 왕들이 그 불붙는 연기를 보고 위하여 울고 가슴을 치며"},{"book":"요한계시록","chapter":18,"verse":10,"text":"그 고난을 무서워하여 멀리 서서 가로되 화 있도다 화 있도다 큰 성, 견고한 성 바벨론이여 일시간에 네 심판이 이르렀다 하리로다"},{"book":"요한계시록","chapter":18,"verse":11,"text":"땅의 상고들이 그를 위하여 울고 애통하는 것은 다시 그 상품을 사는 자가 없음이라"},{"book":"요한계시록","chapter":18,"verse":12,"text":"그 상품은 금과 은과 보석과 진주와 세마포와 자주 옷감과 비단과 붉은 옷감이요 각종 향목과 각종 상아 기명이요 값진 나무와 진유와 철과 옥석으로 만든 각종 기명이요"},{"book":"요한계시록","chapter":18,"verse":13,"text":"계피와 향료와 향과 향유와 유향과 포도주와 감람유와 고운 밀가루와 밀과 소와 양과 말과 수레와 종들과 사람의 영혼들이라"},{"book":"요한계시록","chapter":18,"verse":14,"text":"바벨론아 네 영혼의 탐하던 과실이 네게서 떠났으며 맛 있는 것들과 빛난 것들이 다 없어졌으니 사람들이 결코 이것들을 다시 보지 못하리로다"},{"book":"요한계시록","chapter":18,"verse":15,"text":"바벨론을 인하여 치부한 이 상품의 상고들이 그 고난을 무서워하여 멀리 서서 울고 애통하여"},{"book":"요한계시록","chapter":18,"verse":16,"text":"가로되 화 있도다 화 있도다 큰 성이여 세마포와 자주와 붉은 옷을 입고 금과 보석과 진주로 꾸민 것인데"},{"book":"요한계시록","chapter":18,"verse":17,"text":"그러한 부가 일시간에 망하였도다 각 선장과 각처를 다니는 선객들과 선인들과 바다에서 일하는 자들이 멀리 서서"},{"book":"요한계시록","chapter":18,"verse":18,"text":"그 불붙는 연기를 보고 외쳐 가로되 이 큰 성과 같은 성이 어디 있느뇨 하며"},{"book":"요한계시록","chapter":18,"verse":19,"text":"티끌을 자기 머리에 뿌리고 울고 애통하여 외쳐 가로되 화 있도다 화 있도다 이 큰 성이여 바다에서 배 부리는 모든 자들이 너의 보배로운 상품을 인하여 치부하였더니 일시간에 망하였도다"},{"book":"요한계시록","chapter":18,"verse":20,"text":"하늘과 성도들과 사도들과 선지자들아 그를 인하여 즐거워하라 하나님이 너희를 신원하시는 심판을 그에게 하셨음이라 하더라"},{"book":"요한계시록","chapter":18,"verse":21,"text":"이에 한 힘센 천사가 큰 맷돌 같은 돌을 들어 바다에 던져 가로되 큰 성 바벨론이 이같이 몹시 떨어져 결코 다시 보이지 아니하리로다"},{"book":"요한계시록","chapter":18,"verse":22,"text":"또 거문고 타는 자와 풍류하는 자와 퉁소 부는 자와 나팔 부는 자들의 소리가 결코 다시 네 가운데서 들리지 아니하고 물론 어떠한 세공업자든지 결코 다시 네 가운데서 보이지 아니하고 또 맷돌 소리가 결코 다시 네 가운데서 들리지 아니하고"},{"book":"요한계시록","chapter":18,"verse":23,"text":"등불 빛이 결코 다시 네 가운데서 비취지 아니하고 신랑과 신부의 음성이 결코 다시 네 가운데서 들리지 아니하리로다 너의 상고들은 땅의 왕족들이라 네 복술을 인하여 만국이 미혹되었도다"},{"book":"요한계시록","chapter":18,"verse":24,"text":"선지자들과 성도들과 및 땅 위에서 죽임을 당한 모든 자의 피가 이 성중에서 보였느니라 하더라"},{"book":"요한계시록","chapter":19,"verse":1,"text":"이 일 후에 내가 들으니 하늘에 허다한 무리의 큰 음성 같은 것이 있어 가로되 할렐루야 구원과 영광과 능력이 우리 하나님께 있도다"},{"book":"요한계시록","chapter":19,"verse":2,"text":"그의 심판은 참되고 의로운지라 음행으로 땅을 더럽게 한 큰 음녀를 심판하사 자기 종들의 피를 그의 손에 갚으셨도다 하고"},{"book":"요한계시록","chapter":19,"verse":3,"text":"두번째 가로되 할렐루야 하더니 그 연기가 세세토록 올라가더라"},{"book":"요한계시록","chapter":19,"verse":4,"text":"또 이십 사 장로와 네 생물이 엎드려 보좌에 앉으신 하나님께 경배하여 가로되 아멘 할렐루야 하니"},{"book":"요한계시록","chapter":19,"verse":5,"text":"보좌에서 음성이 나서 가로되 하나님의 종들 곧 그를 경외하는 너희들아 무론대소하고 다 우리 하나님께 찬송하라 하더라"},{"book":"요한계시록","chapter":19,"verse":6,"text":"또 내가 들으니 허다한 무리의 음성도 같고 많은 물 소리도 같고 큰 뇌성도 같아서 가로되 할렐루야 주 우리 하나님 곧 전능하신 이가 통치하시도다"},{"book":"요한계시록","chapter":19,"verse":7,"text":"우리가 즐거워하고 크게 기뻐하여 그에게 영광을 돌리세 어린 양의 혼인 기약이 이르렀고 그 아내가 예비하였으니"},{"book":"요한계시록","chapter":19,"verse":8,"text":"그에게 허락하사 빛나고 깨끗한 세마포를 입게 하셨은즉 이 세마포는 성도들의 옳은 행실이로다 하더라"},{"book":"요한계시록","chapter":19,"verse":9,"text":"천사가 내게 말하기를 기록하라 어린 양의 혼인 잔치에 청함을 입은 자들이 복이 있도다 하고 또 내게 말하되 이것은 하나님의 참되신 말씀이라 하기로"},{"book":"요한계시록","chapter":19,"verse":10,"text":"내가 그 발 앞에 엎드려 경배하려 하니 그가 나더러 말하기를 나는 너와 및 예수의 증거를 받은 네 형제들과 같이 된 종이니 삼가 그리하지 말고 오직 하나님께 경배하라 예수의 증거는 대언의 영이라 하더라"},{"book":"요한계시록","chapter":19,"verse":11,"text":"또 내가 하늘이 열린 것을 보니 보라 백마와 탄 자가 있으니 그 이름은 충신과 진실이라 그가 공의로 심판하며 싸우더라"},{"book":"요한계시록","chapter":19,"verse":12,"text":"그 눈이 불꽃 같고 그 머리에 많은 면류관이 있고 또 이름 쓴 것이 하나가 있으니 자기 밖에 아는 자가 없고"},{"book":"요한계시록","chapter":19,"verse":13,"text":"또 그가 피 뿌린 옷을 입었는데 그 이름은 하나님의 말씀이라 칭하더라"},{"book":"요한계시록","chapter":19,"verse":14,"text":"하늘에 있는 군대들이 희고 깨끗한 세마포를 입고 백마를 타고 그를 따르더라"},{"book":"요한계시록","chapter":19,"verse":15,"text":"그의 입에서 이한 검이 나오니 그것으로 만국을 치겠고 친히 저희를 철장으로 다스리며 또 친히 하나님 곧 전능하신 이의 맹렬한 진노의 포도주 틀을 밟겠고"},{"book":"요한계시록","chapter":19,"verse":16,"text":"그 옷과 그 다리에 이름 쓴 것이 있으니 만왕의 왕이요 만주의 주라 하였더라"},{"book":"요한계시록","chapter":19,"verse":17,"text":"또 내가 보니 한 천사가 해에 서서 공중에 나는 모든 새를 향하여 큰 음성으로 외쳐 가로되 와서 하나님의 큰 잔치에 모여"},{"book":"요한계시록","chapter":19,"verse":18,"text":"왕들의 고기와 장군들의 고기와 장사들의 고기와 말들과 그 탄 자들의 고기와 자유한 자들이나 종들이나 무론대소하고 모든 자의 고기를 먹으라 하더라"},{"book":"요한계시록","chapter":19,"verse":19,"text":"또 내가 보매 그 짐승과 땅의 임금들과 그 군대들이 모여 그 말 탄 자와 그의 군대로 더불어 전쟁을 일으키다가"},{"book":"요한계시록","chapter":19,"verse":20,"text":"짐승이 잡히고 그 앞에서 이적을 행하던 거짓 선지자도 함께 잡혔으니 이는 짐승의 표를 받고 그의 우상에게 경배하던 자들을 이적으로 미혹하던 자라 이 둘이 산채로 유황불 붙는 못에 던지우고"},{"book":"요한계시록","chapter":19,"verse":21,"text":"그 나머지는 말 탄 자의 입으로 나오는 검에 죽으매 모든 새가 그 고기로 배불리우더라"},{"book":"요한계시록","chapter":20,"verse":1,"text":"또 내가 보매 천사가 무저갱 열쇠와 큰 쇠사슬을 그 손에 가지고 하늘로서 내려와서"},{"book":"요한계시록","chapter":20,"verse":2,"text":"용을 잡으니 곧 옛 뱀이요 마귀요 사단이라 잡아 일천년 동안 결박하여"},{"book":"요한계시록","chapter":20,"verse":3,"text":"무저갱에 던져 잠그고 그 위에 인봉하여 천년이 차도록 다시는 만국을 미혹하지 못하게 하였다가 그 후에는 반드시 잠간 놓이리라"},{"book":"요한계시록","chapter":20,"verse":4,"text":"또 내가 보좌들을 보니 거기 앉은 자들이 있어 심판하는 권세를 받았더라 또 내가 보니 예수의 증거와 하나님의 말씀을 인하여 목 베임을 받은 자의 영혼들과 또 짐승과 그의 우상에게 경배하지도 아니하고 이마와 손에 그의 표를 받지도 아니한 자들이 살아서 그리스도로 더불어 천년 동안 왕노릇 하니"},{"book":"요한계시록","chapter":20,"verse":5,"text":"(그 나머지 죽은 자들은 그 천년이 차기까지 살지 못하더라) 이는 첫째 부활이라"},{"book":"요한계시록","chapter":20,"verse":6,"text":"이 첫째 부활에 참예하는 자들은 복이 있고 거룩하도다 둘째 사망이 그들을 다스리는 권세가 없고 도리어 그들이 하나님과 그리스도의 제사장이 되어 천년 동안 그리스도로 더불어 왕노릇 하리라"},{"book":"요한계시록","chapter":20,"verse":7,"text":"천년이 차매 사단이 그 옥에서 놓여"},{"book":"요한계시록","chapter":20,"verse":8,"text":"나와서 땅의 사방 백성 곧 곡과 마곡을 미혹하고 모아 싸움을 붙이리니 그 수가 바다 모래 같으리라"},{"book":"요한계시록","chapter":20,"verse":9,"text":"저희가 지면에 널리 퍼져 성도들의 진과 사랑하시는 성을 두르매 하늘에서 불이 내려와 저희를 소멸하고"},{"book":"요한계시록","chapter":20,"verse":10,"text":"또 저희를 미혹하는 마귀가 불과 유황 못에 던지우니 거기는 그 짐승과 거짓 선지자도 있어 세세토록 밤낮 괴로움을 받으리라"},{"book":"요한계시록","chapter":20,"verse":11,"text":"또 내가 크고 흰 보좌와 그 위에 앉으신 자를 보니 땅과 하늘이 그 앞에서 피하여 간데 없더라"},{"book":"요한계시록","chapter":20,"verse":12,"text":"또 내가 보니 죽은 자들이 무론 대소하고 그 보좌 앞에 섰는데 책들이 펴 있고 또 다른 책이 펴졌으니 곧 생명책이라 죽은 자들이 자기 행위를 따라 책들에 기록된대로 심판을 받으니"},{"book":"요한계시록","chapter":20,"verse":13,"text":"바다가 그 가운데서 죽은 자들을 내어주고 또 사망과 음부도 그 가운데서 죽은 자들을 내어주매 각 사람이 자기의 행위대로 심판을 받고"},{"book":"요한계시록","chapter":20,"verse":14,"text":"사망과 음부도 불못에 던지우니 이것은 둘째 사망 곧 불못이라"},{"book":"요한계시록","chapter":20,"verse":15,"text":"누구든지 생명책에 기록되지 못한 자는 불못에 던지우더라"},{"book":"요한계시록","chapter":21,"verse":1,"text":"또 내가 새 하늘과 새 땅을 보니 처음 하늘과 처음 땅이 없어졌고 바다도 다시 있지 않더라"},{"book":"요한계시록","chapter":21,"verse":2,"text":"또 내가 보매 거룩한 성 새 예루살렘이 하나님께로부터 하늘에서 내려오니 그 예비한 것이 신부가 남편을 위하여 단장한 것 같더라"},{"book":"요한계시록","chapter":21,"verse":3,"text":"내가 들으니 보좌에서 큰 음성이 나서 가로되 보라 하나님의 장막이 사람들과 함께 있으매 하나님이 저희와 함께 거하시리니 저희는 하나님의 백성이 되고 하나님은 친히 저희와 함께 계셔서"},{"book":"요한계시록","chapter":21,"verse":4,"text":"모든 눈물을 그 눈에서 씻기시매 다시 사망이 없고 애통하는 것이나 곡하는 것이나 아픈 것이 다시 있지 아니하리니 처음 것들이 다 지나갔음이러라"},{"book":"요한계시록","chapter":21,"verse":5,"text":"보좌에 앉으신 이가 가라사대 보라 내가 만물을 새롭게 하노라 하시고 또 가라사대 이 말은 신실하고 참되니 기록하라 하시고"},{"book":"요한계시록","chapter":21,"verse":6,"text":"또 내게 말씀하시되 이루었도다 나는 알파와 오메가요 처음과 나중이라 내가 생명수 샘물로 목 마른 자에게 값 없이 주리니"},{"book":"요한계시록","chapter":21,"verse":7,"text":"이기는 자는 이것들을 유업으로 얻으리라 나는 저의 하나님이 되고 그는 내 아들이 되리라"},{"book":"요한계시록","chapter":21,"verse":8,"text":"그러나 두려워하는 자들과 믿지 아니하는 자들과 흉악한 자들과 살인자들과 행음자들과 술객들과 우상 숭배자들과 모든 거짓말 하는 자들은 불과 유황으로 타는 못에 참예하리니 이것이 둘째 사망이라"},{"book":"요한계시록","chapter":21,"verse":9,"text":"일곱 대접을 가지고 마지막 일곱 재앙을 담은 일곱 천사중 하나가 나아와서 내게 말하여 가로되 이리 오라 내가 신부 곧 어린 양의 아내를 네게 보이리라 하고"},{"book":"요한계시록","chapter":21,"verse":10,"text":"성령으로 나를 데리고 크고 높은 산으로 올라가 하나님께로부터 하늘에서 내려오는 거룩한 성 예루살렘을 보이니"},{"book":"요한계시록","chapter":21,"verse":11,"text":"하나님의 영광이 있으매 그 성의 빛이 지극히 귀한 보석 같고 벽옥과 수정 같이 맑더라"},{"book":"요한계시록","chapter":21,"verse":12,"text":"크고 높은 성곽이 있고 열 두 문이 있는데 문에 열 두 천사가 있고 그 문들 위에 이름을 썼으니 이스라엘 자손 열 두 지파의 이름들이라"},{"book":"요한계시록","chapter":21,"verse":13,"text":"동편에 세 문, 북편에 세 문, 남편에 세 문, 서편에 세 문이니"},{"book":"요한계시록","chapter":21,"verse":14,"text":"그 성에 성곽은 열 두 기초석이 있고 그 위에 어린 양의 십 이 사도의 열 두 이름이 있더라"},{"book":"요한계시록","chapter":21,"verse":15,"text":"내게 말하는 자가 그 성과 그 문들과 성곽을 척량하려고 금 갈대를 가졌더라"},{"book":"요한계시록","chapter":21,"verse":16,"text":"그 성은 네모가 반듯하여 장광이 같은지라 그 갈대로 그 성을 척량하니 일만 이천 스다디온이요 장과 광과 고가 같더라"},{"book":"요한계시록","chapter":21,"verse":17,"text":"그 성곽을 척량하매 일백 사십 사 규빗이니 사람의 척량 곧 천사의 척량이라"},{"book":"요한계시록","chapter":21,"verse":18,"text":"그 성곽은 벽옥으로 쌓였고 그 성은 정금인데 맑은 유리 같더라"},{"book":"요한계시록","chapter":21,"verse":19,"text":"그 성의 성곽의 기초석은 각색 보석으로 꾸몄는데 첫째 기초석은 벽옥이요 둘째는 남보석이요 세째는 옥수요 네째는 녹보석이요"},{"book":"요한계시록","chapter":21,"verse":20,"text":"다섯째는 홍마노요 여섯째는 홍보석이요 일곱째는 황옥이요 여덟째는 녹옥이요 아홉째는 담황옥이요 열째는 비취옥이요 열 한째는 청옥이요 열 둘째는 자정이라"},{"book":"요한계시록","chapter":21,"verse":21,"text":"그 열 두 문은 열 두 진주니 문마다 한 진주요 성의 길은 맑은 유리 같은 정금이더라"},{"book":"요한계시록","chapter":21,"verse":22,"text":"성안에 성전을 내가 보지 못하였으니 이는 주 하나님 곧 전능하신 이와 및 어린 양이 그 성전이심이라"},{"book":"요한계시록","chapter":21,"verse":23,"text":"그 성은 해나 달의 비췸이 쓸데 없으니 이는 하나님의 영광이 비취고 어린 양이 그 등이 되심이라"},{"book":"요한계시록","chapter":21,"verse":24,"text":"만국이 그 빛 가운데로 다니고 땅의 왕들이 자기 영광을 가지고 그리로 들어오리라"},{"book":"요한계시록","chapter":21,"verse":25,"text":"성문들을 낮에 도무지 닫지 아니하리니 거기는 밤이 없음이라"},{"book":"요한계시록","chapter":21,"verse":26,"text":"사람들이 만국의 영광과 존귀를 가지고 그리로 들어오겠고"},{"book":"요한계시록","chapter":21,"verse":27,"text":"무엇이든지 속된 것이나 가증한 일 또는 거짓말 하는 자는 결코 그리로 들어오지 못하되 오직 어린 양의 생명책에 기록된 자들뿐이라"},{"book":"요한계시록","chapter":22,"verse":1,"text":"또 저가 수정 같이 맑은 생명수의 강을 내게 보이니 하나님과 및 어린 양의 보좌로부터 나서"},{"book":"요한계시록","chapter":22,"verse":2,"text":"길 가운데로 흐르더라 강 좌우에 생명 나무가 있어 열 두가지 실과를 맺히되 달마다 그 실과를 맺히고 그 나무 잎사귀들은 만국을 소성하기 위하여 있더라"},{"book":"요한계시록","chapter":22,"verse":3,"text":"다시 저주가 없으며 하나님과 그 어린 양의 보좌가 그 가운데 있으리니 그의 종들이 그를 섬기며"},{"book":"요한계시록","chapter":22,"verse":4,"text":"그의 얼굴을 볼터이요 그의 이름도 저희 이마에 있으리라"},{"book":"요한계시록","chapter":22,"verse":5,"text":"다시 밤이 없겠고 등불과 햇빛이 쓸데 없으니 이는 주 하나님이 저희에게 비취심이라 저희가 세세토록 왕노릇하리로다"},{"book":"요한계시록","chapter":22,"verse":6,"text":"또 그가 내게 말하기를 이 말은 신실하고 참된지라 주 곧 선지자들의 영의 하나님이 그의 종들에게 결코 속히 될 일을 보이시려고 그의 천사를 보내셨도다"},{"book":"요한계시록","chapter":22,"verse":7,"text":"보라 내가 속히 오리니 이 책의 예언의 말씀을 지키는 자가 복이 있으리라 하더라"},{"book":"요한계시록","chapter":22,"verse":8,"text":"이것들을 보고 들은 자는 나 요한이니 내가 듣고 볼 때에 이 일을 내게 보이던 천사의 발앞에 경배하려고 엎드렸더니"},{"book":"요한계시록","chapter":22,"verse":9,"text":"저가 내게 말하기를 나는 너와 네 형제 선지자들과 또 이 책의 말을 지키는 자들과 함께 된 종이니 그리하지 말고 오직 하나님께 경배하라 하더라"},{"book":"요한계시록","chapter":22,"verse":10,"text":"또 내게 말하되 이 책의 예언의 말씀을 인봉하지 말라 때가 가까우니라"},{"book":"요한계시록","chapter":22,"verse":11,"text":"불의를 하는 자는 그대로 불의를 하고 더러운 자는 그대로 더럽고 의로운 자는 그대로 의를 행하고 거룩한 자는 그대로 거룩되게 하라"},{"book":"요한계시록","chapter":22,"verse":12,"text":"보라 내가 속히 오리니 내가 줄 상이 내게 있어 각 사람에게 그의 일한대로 갚아 주리라"},{"book":"요한계시록","chapter":22,"verse":13,"text":"나는 알파와 오메가요 처음과 나중이요 시작과 끝이라"},{"book":"요한계시록","chapter":22,"verse":14,"text":"그 두루마기를 빠는 자들은 복이 있으니 이는 저희가 생명 나무에 나아가며 문들을 통하여 성에 들어갈 권세를 얻으려 함이로다"},{"book":"요한계시록","chapter":22,"verse":15,"text":"개들과 술객들과 행음자들과 살인자들과 우상 숭배자들과 및 거짓말을 좋아하며 지어내는 자마다 성밖에 있으리라"},{"book":"요한계시록","chapter":22,"verse":16,"text":"나 예수는 교회들을 위하여 내 사자를 보내어 이것들을 너희에게 증거하게 하였노라 나는 다윗의 뿌리요 자손이니 곧 광명한 새벽별이라 하시더라"},{"book":"요한계시록","chapter":22,"verse":17,"text":"성령과 신부가 말씀하시기를 오라 하시는도다 듣는 자도 오라 할 것이요 목마른 자도 올 것이요 또 원하는 자는 값 없이 생명수를 받으라 하시더라"},{"book":"요한계시록","chapter":22,"verse":18,"text":"내가 이 책의 예언의 말씀을 듣는 각인에게 증거하노니 만일 누구든지 이것들 외에 더하면 하나님이 이 책에 기록된 재앙들을 그에게 더하실 터이요"},{"book":"요한계시록","chapter":22,"verse":19,"text":"만일 누구든지 이 책의 예언의 말씀에서 제하여 버리면 하나님이 이 책에 기록된 생명 나무와 및 거룩한 성에 참예함을 제하여 버리시리라"},{"book":"요한계시록","chapter":22,"verse":20,"text":"이것들을 증거하신 이가 가라사대 내가 진실로 속히 오리라 하시거늘 아멘 주 예수여 오시옵소서"},{"book":"요한계시록","chapter":22,"verse":21,"text":"주 예수의 은혜가 모든 자들에게 있을찌어다 아멘"}];

