function renderDashboard(){
  const all=verses(), m=mem();
  const mastered=all.filter(isVerseMemorized).length;
  const rate=all.length?Math.round(mastered/all.length*1000)/10:0;

  el.dashboard.innerHTML=card([
    ["🧠 전체 암기",mastered+" / 404절"],
    ["📈 전체 달성률",rate+"%"]
  ]);

  el.progressBar.style.width=rate+"%";

  const selected=selectedMemoryChapter();
  el.chapterGrid.innerHTML=[...Array(22)].map((_,i)=>{
    const ch=i+1;
    const arr=all.filter(v=>v.chapter===ch);
    const done=arr.filter(isVerseMemorized).length;
    const exp=EXPECTED[ch];
    const pct=exp?Math.round(done/exp*100):0;
    const medal=pct===100?"🏅":"";
    const selectedClass=selected===ch?" selectedChapter":"";
    const heat=pct>=80?" heatHigh":pct>=40?" heatMid":pct>0?" heatLow":"";
    return `<div class="chapterBox memoryChapterBtn${selectedClass}${heat}" data-chapter="${ch}">
      <b>${medal} ${ch}장</b>
      <div class="chapterProgressText">암기 ${done}/${exp}</div>
      <div class="chapterMiniBar"><span style="width:${pct}%"></span></div>
      <small>${pct}%</small>
    </div>`;
  }).join("");

  el.chapterGrid.querySelectorAll(".memoryChapterBtn").forEach(btn=>{
    btn.onclick=()=>{
      const ch=Number(btn.dataset.chapter);
      setSelectedMemoryChapter(selectedMemoryChapter()===ch?0:ch);
      renderDashboard();
    };
  });

  renderMemoryChapterCheck();
  renderTodayMemorized();
  applyMemoryStatusCollapse();
}
