function customNode(id){return document.getElementById(id)}

function fillCustomChapterSelect(sel){
  if(!sel)return;
  const chapters=[...new Set(verses().map(v=>v.chapter))].sort((a,b)=>a-b);
  const cur=sel.value;
  sel.innerHTML=chapters.map(ch=>`<option value="${ch}">${ch}장</option>`).join("");
  if(chapters.includes(Number(cur)))sel.value=cur;
  else if(sel.options.length)sel.value=sel.options[0].value;
}

function fillCustomVerseSelect(sel,ch,preferLast=false){
  if(!sel)return;
  const arr=verses().filter(v=>v.chapter===Number(ch)).sort((a,b)=>a.verse-b.verse);
  const cur=sel.value;
  sel.innerHTML=arr.map(v=>`<option value="${v.verse}">${v.verse}절</option>`).join("");
  if(arr.some(v=>v.verse===Number(cur)))sel.value=cur;
  else if(sel.options.length)sel.value=preferLast?sel.options[sel.options.length-1].value:sel.options[0].value;
}

function renderCustomRangeOptions(){
  const sc=customNode("customStartChapter"), sv=customNode("customStartVerse"), ec=customNode("customEndChapter"), ev=customNode("customEndVerse");
  if(!sc||!sv||!ec||!ev)return;
  const hadStart=sc.value, hadEnd=ec.value;
  fillCustomChapterSelect(sc);
  fillCustomChapterSelect(ec);
  if(!hadEnd && ec.options.length)ec.value=ec.options[ec.options.length-1].value;
  fillCustomVerseSelect(sv,sc.value,false);
  fillCustomVerseSelect(ev,ec.value,true);
}

function verseOrder(ch,vs){return Number(ch)*1000+Number(vs)}

function getCustomRangeVerses(){
  const sc=customNode("customStartChapter"), sv=customNode("customStartVerse"), ec=customNode("customEndChapter"), ev=customNode("customEndVerse");
  if(!sc||!sv||!ec||!ev)return [];
  const start=verseOrder(sc.value,sv.value);
  const end=verseOrder(ec.value,ev.value);
  if(start>end)return [];
  return verses()
    .filter(v=>verseOrder(v.chapter,v.verse)>=start && verseOrder(v.chapter,v.verse)<=end)
    .sort((a,b)=>verseOrder(a.chapter,a.verse)-verseOrder(b.chapter,b.verse));
}

function updateCustomRangeUI(){
  const panel=customNode("customRangePanel");
  const preview=customNode("rangePreview");
  const isCustom=el.rangeSelect && el.rangeSelect.value==="custom";
  if(panel)panel.classList.toggle("hidden",!isCustom);
  if(!preview)return;

  if(isCustom){
    renderCustomRangeOptions();
    const sc=customNode("customStartChapter"), sv=customNode("customStartVerse"), ec=customNode("customEndChapter"), ev=customNode("customEndVerse");
    const list=getCustomRangeVerses();
    if(!list.length)preview.textContent="시작 범위가 종료 범위보다 앞서야 합니다.";
    else preview.textContent=`시험 범위: 계 ${sc.value}:${sv.value} ~ 계 ${ec.value}:${ev.value} · 총 ${list.length}절`;
    return;
  }

  if(el.rangeSelect.value==="all"){
    preview.textContent=`시험 범위: 전체 · 총 ${verses().length}절`;
  }else{
    const ch=Number(el.rangeSelect.value);
    const cnt=verses().filter(v=>v.chapter===ch).length;
    preview.textContent=cnt?`시험 범위: 계 ${ch}장 · 총 ${cnt}절`:"";
  }
}

