function getExamBasePool(){
  const all=verses(), m=mem(), mode=el.modeSelect.value;
  let pool=el.rangeSelect.value==="all"?all:(el.rangeSelect.value==="custom"?getCustomRangeVerses():all.filter(v=>v.chapter==el.rangeSelect.value));
  if(mode==="review") pool=getSmartReviewVerses(pool);
  if(mode==="favorite") pool=pool.filter(v=>m[key(v)]?.fav);
  if(mode==="confuse") pool=pool.filter(v=>m[key(v)]?.confuse && !m[key(v)]?.resolved);
  return pool.sort((a,b)=>verseOrder(a.chapter,a.verse)-verseOrder(b.chapter,b.verse));
}

function questionTargetForMode(q){
  const mode=el.modeSelect.value==="review"?"write":el.modeSelect.value;
  if(mode==="ref")return `요한계시록 ${q.chapter}:${q.verse}`;
  if(mode==="blank")return blankAnswer(q.text);
  return q.text;
}

function checkAnswerForMode(q,user){
  const mode=el.modeSelect.value==="review"?"write":el.modeSelect.value;
  const target=questionTargetForMode(q);
  if(mode==="ref"){
    const u=String(user||"").replace(/\s/g,"");
    return {ok:u===`요한계시록${q.chapter}:${q.verse}` || u===`계${q.chapter}:${q.verse}` || u===`${q.chapter}:${q.verse}`,target};
  }
  return {ok:safeExactCompare(String(user||"").trim(),target),target};
}



function isWrongForNote(v){
  const r=mem()[key(v)]||{};
  return !!r.wrongNoteActive || ((r.wrongNoteWrong||0)>0) || ((r.wrong||0)>0 && !r.wrongNoteResolvedAt);
}

function noteReason(v){
  const r=mem()[key(v)]||{};
  if(isWrongForNote(v))return `🔴 오답 ${r.wrongNoteWrong||r.wrong||1}회`;
  if(r.confuse && !r.resolved)return "🟡 헷갈림 표시";
  if(r.fav)return "⭐ 즐겨찾기";
  if(r.next && r.next<=Date.now())return "⏰ 복습 날짜 도래";
  if(r.lastStudied){
    const days=Math.floor((Date.now()-new Date(r.lastStudied+"T00:00:00").getTime())/86400000);
    if(days>=7)return `⏰ ${days}일 동안 복습 안 함`;
  }
  return "추천";
}

function uniqueVerses(list){
  const seen=new Set();
  return list.filter(v=>{
    const kq=key(v);
    if(seen.has(kq))return false;
    seen.add(kq);
    return true;
  });
}

function wrongNoteVerses(includeResolved=false){
  return verses()
    .filter(v=>{
      const r=mem()[key(v)]||{};
      const active=isWrongForNote(v);
      return includeResolved ? (active || !!r.wrongNoteResolvedAt) : active;
    })
    .sort((a,b)=>{
      const ra=mem()[key(a)]||{}, rb=mem()[key(b)]||{};
      return (rb.wrongNoteWrong||rb.wrong||0)-(ra.wrongNoteWrong||ra.wrong||0) || verseOrder(a.chapter,a.verse)-verseOrder(b.chapter,b.verse);
    });
}

function getSmartReviewVerses(base=null){
  const all=(base||verses()).slice();
  const m=mem();
  const wrong=all.filter(v=>isWrongForNote(v));
  const confuse=all.filter(v=>m[key(v)]?.confuse && !m[key(v)]?.resolved);
  const fav=all.filter(v=>m[key(v)]?.fav);
  const due=all.filter(v=>m[key(v)]?.next && m[key(v)].next<=Date.now());
  const old=all.filter(v=>{
    const r=m[key(v)]||{};
    if(!r.lastStudied)return false;
    const days=Math.floor((Date.now()-new Date(r.lastStudied+"T00:00:00").getTime())/86400000);
    return days>=7;
  }).sort((a,b)=>{
    const ra=m[key(a)]||{}, rb=m[key(b)]||{};
    return String(ra.lastStudied||"").localeCompare(String(rb.lastStudied||""));
  });
  return uniqueVerses([...wrong,...confuse,...fav,...due,...old]).sort((a,b)=>{
    const ra=noteReason(a), rb=noteReason(b);
    const priority=r=>r.startsWith("🔴")?0:r.startsWith("🟡")?1:r.startsWith("⭐")?2:3;
    return priority(ra)-priority(rb) || verseOrder(a.chapter,a.verse)-verseOrder(b.chapter,b.verse);
  });
}

