function reviewSettings(){
  const s=settings();
  s.reviewCompletedDates=s.reviewCompletedDates||[];
  return s;
}

function studiedDatesForReview(){
  const m=mem(), today=dateISO();
  const dates=new Set();
  Object.values(m).forEach(r=>{
    if(r && r.lastStudied && r.lastStudied<today) dates.add(r.lastStudied);
  });
  return [...dates].sort();
}

function getPendingReviewDate(){
  const s=reviewSettings();
  const done=new Set(s.reviewCompletedDates||[]);
  return studiedDatesForReview().find(d=>!done.has(d)) || null;
}

function getTodayReviewVerses(base=null){
  const all=base||verses();
  const target=getPendingReviewDate();
  if(!target)return [];
  const m=mem();
  return all.filter(v=>(m[key(v)]||{}).lastStudied===target);
}

function markReviewDateDone(date){
  if(!date)return;
  const s=reviewSettings();
  s.reviewCompletedDates=s.reviewCompletedDates||[];
  if(!s.reviewCompletedDates.includes(date))s.reviewCompletedDates.push(date);
  set(K.settings,s);
}

function formatReviewDate(iso){
  if(!iso)return "";
  const [y,m,d]=iso.split("-");
  return `${Number(m)}/${Number(d)} 학습분`;
}




function renderReadChapters(){
  if(!el.readChapterSelect)return;
  const all=verses();
  const current=el.readChapterSelect.value;
  const chapters=[...new Set(all.map(v=>v.chapter))].sort((a,b)=>a-b);
  el.readChapterSelect.innerHTML="";
  chapters.forEach(ch=>{
    el.readChapterSelect.innerHTML+=`<option value="${ch}">${ch}장</option>`;
  });
  if([...el.readChapterSelect.options].some(o=>o.value===current)){
    el.readChapterSelect.value=current;
  }else if(el.readChapterSelect.options.length){
    el.readChapterSelect.value=el.readChapterSelect.options[0].value;
  }
}

function renderReadingHome(){
  if(!el.lastReadInfo)return;
  const s=settings();
  const last=s.lastRead || {chapter:1,verse:1};
  el.lastReadInfo.innerHTML=`<b>마지막 읽은 곳</b><br>요한계시록 ${last.chapter||1}장 ${last.verse||1}절`;
  renderBookmarks();
}


function loadReadingTimer(){
  const s=settings();
  readingTimer=s.readingTimer || {chapter:null,elapsed:0,start:0,running:false};
}

function saveReadingTimerState(){
  const s=settings();
  s.readingTimer=readingTimer;
  set(K.settings,s);
}

function getReadingElapsedSeconds(){
  let total=readingTimer.elapsed||0;
  if(readingTimer.running && readingTimer.start){
    total+=Math.floor((Date.now()-readingTimer.start)/1000);
  }
  return Math.max(0,total);
}

function formatReadingTime(sec){
  sec=Math.max(0,Number(sec)||0);
  const h=Math.floor(sec/3600);
  const m=Math.floor((sec%3600)/60);
  const s=sec%60;
  return h?`${String(h).padStart(2,"0")}:${String(m).padStart(2,"0")}:${String(s).padStart(2,"0")}`:`${String(m).padStart(2,"0")}:${String(s).padStart(2,"0")}`;
}

function updateReadingTimerUI(){
  const display=$("readingTimerDisplay");
  const startBtn=$("startReadingBtn");
  const pauseBtn=$("pauseReadingBtn");
  if(display)display.textContent=`읽는 시간 ${formatReadingTime(getReadingElapsedSeconds())}`;
  if(startBtn){
    startBtn.textContent=readingTimer.running ? "▶ 읽는 중..." : (getReadingElapsedSeconds()>0 ? "▶ 이어서 읽기" : "▶ 읽기 시작");
    startBtn.disabled=!!readingTimer.running;
  }
  if(pauseBtn){
    pauseBtn.classList.toggle("hidden",!readingTimer.running && getReadingElapsedSeconds()===0);
    pauseBtn.disabled=!readingTimer.running;
  }
}


function ensureReadingTimerInterval(){
  if(window.__gmReadingTimerInterval)return;
  window.__gmReadingTimerInterval=setInterval(()=>{
    try{ updateReadingTimerUI(); }catch(e){ console.error(e); }
  },1000);
}

ensureReadingTimerInterval();

function startReadingTimerManual(){
  ensureReadingTimerInterval();
  const ch=Number(el.readChapterSelect?.value||1);
  if(readingTimer.running)return;
  if(readingTimer.chapter!==ch){
    readingTimer={chapter:ch,elapsed:0,start:0,running:false};
  }
  readingTimer.running=true;
  readingTimer.start=Date.now();
  saveReadingTimerState();
  updateReadingTimerUI();
}

function pauseReadingTimer(){
  if(!readingTimer.running)return;
  readingTimer.elapsed=getReadingElapsedSeconds();
  readingTimer.running=false;
  readingTimer.start=0;
  saveReadingTimerState();
  updateReadingTimerUI();
}

function resetReadingTimer(ch){
  readingTimer={chapter:ch,elapsed:0,start:0,running:false};
  saveReadingTimerState();
  updateReadingTimerUI();
}

function confirmReadingChapterChange(nextAction){
  if(getReadingElapsedSeconds()>0 && !confirm("현재 읽기 시간이 있습니다.\n장을 변경하면 현재 읽기 시간이 초기화됩니다.\n계속 이동할까요?")){
    return false;
  }
  nextAction();
  return true;
}

function getReadingCollapsed(){
  return settings().readingCollapsed || false;
}

function setReadingCollapsed(value){
  const s=settings();
  s.readingCollapsed=!!value;
  setSettings(s);
}

function applyReadingCollapse(){
  if(!el.readingContent || !el.toggleReadingBtn)return;
  const collapsed=getReadingCollapsed();
  el.readingContent.classList.toggle("hidden", collapsed);
  el.toggleReadingBtn.textContent=collapsed ? "▼ 본문 펼치기" : "▲ 본문 접기";
}

function renderReading(){
  if(!el.readingContent || !el.readChapterSelect)return;
  const all=verses();
  if(!all.length){
    el.readingContent.innerHTML="<p class='note'>등록된 본문이 없습니다.</p>";
    return;
  }
  if(!el.readChapterSelect.value){
    renderReadChapters();
  }
  const ch=Number(el.readChapterSelect.value||1);
  loadReadingTimer();
  updateReadingTimerUI();
  const hide=el.readModeSelect && el.readModeSelect.value==="hide";
  const arr=all.filter(v=>v.chapter===ch).sort((a,b)=>a.verse-b.verse);
  el.readingContent.innerHTML=arr.map(v=>{
    const kq=key(v);
    const r=mem()[kq]||{};
    return `<div class="verseRead" id="versebox-${v.chapter}-${v.verse}" onclick="saveLastRead(${v.chapter},${v.verse})">
      <b>${v.chapter}:${v.verse}</b>
      <span class="verseText ${hide?"hiddenText":""}" id="read-${v.chapter}-${v.verse}">${esc(v.text)}</span>
      <div class="smallBtns">
        <button class="secondary" onclick="event.stopPropagation();toggleReadText('${v.chapter}-${v.verse}')">보기/가리기</button>
        <button class="secondary" onclick="event.stopPropagation();markReadFavorite('${kq}')">${r.fav?"⭐ 해제":"⭐ 저장"}</button>
        <button class="secondary" onclick="event.stopPropagation();markReadConfuse('${kq}')">📝 헷갈림</button>
        <button class="secondary" onclick="event.stopPropagation();addBookmark(${v.chapter},${v.verse})">📌 책갈피</button>
      </div>
    </div>`;
  }).join("") || "<p class='note'>이 장의 본문을 찾지 못했습니다. 백업을 불러왔는지 확인해주세요.</p>";
  applyReadingCollapse();
  applyRecordPanelCollapses();
}

window.toggleReadText=function(id){
  const node=document.getElementById("read-"+id);
  if(node)node.classList.toggle("hiddenText");
}

window.markReadFavorite=function(kq){
  const m=mem();
  m[kq]=m[kq]||{};
  m[kq].fav=!m[kq].fav;
  const nowFav=m[kq].fav;
  setMem(m);
  renderReading();
  renderLists();
  showMiniToast(nowFav ? "즐겨찾기에 저장했습니다." : "즐겨찾기를 해제했습니다.");
}

window.markReadConfuse=function(kq){
  const v=verses().find(x=>key(x)===kq);
  if(!v)return;
  const m=mem();
  m[kq]=m[kq]||{};
  const memo=prompt(`요한계시록 ${v.chapter}:${v.verse}\n헷갈린 이유를 적어둘까요?`, m[kq].confuseMemo||"");
  if(memo!==null){
    m[kq].confuse=true;
    m[kq].confuseMemo=memo;
    m[kq].resolved=false;
    setMem(m);
    renderAll();
  }
}

