function changeReadChapter(delta){
  if(!el.readChapterSelect)return;
  const opts=[...el.readChapterSelect.options].map(o=>Number(o.value));
  const cur=Number(el.readChapterSelect.value);
  const idx=opts.indexOf(cur);
  const next=opts[idx+delta];
  if(next){
    confirmReadingChapterChange(()=>{
      el.readChapterSelect.value=String(next);
      resetReadingTimer(next);
      renderReading();
    });
  }
}

