function calcStreaks(){
  const days=[...new Set(records().map(r=>r.dateISO).filter(Boolean))].sort();
  const setDays=new Set(days);
  let cur=0, d=new Date();
  while(setDays.has(dateISO(d))){cur++; d.setDate(d.getDate()-1);}
  let best=0, run=0, prev=null;
  for(const iso of days){
    const dt=new Date(iso+"T00:00:00");
    if(prev){
      const gap=Math.round((dt-prev)/86400000);
      run=gap===1?run+1:1;
    }else run=1;
    best=Math.max(best,run);
    prev=dt;
  }
  return {current:cur,best,totalDays:days.length};
}

function renderDeepStats(){
  if(!el.deepStats)return;
  const rs=records(), all=verses(), m=mem();
  const totalTime=rs.reduce((s,r)=>s+(Number(r.duration)||0),0);
  const totalTests=rs.length;
  const solved=rs.reduce((s,r)=>s+recordQuestionCount(r),0);
  const correct=rs.reduce((s,r)=>s+(Number(r.correct)||0),0);
  const mastered=all.filter(v=>(m[key(v)]?.streak||0)>=3 || m[key(v)]?.manualMemorized).length;
  const st=calcStreaks();
  el.deepStats.innerHTML=card([
    ["누적 공부일",st.totalDays+"일"],
    ["현재 연속",st.current+"일"],
    ["최고 연속",st.best+"일"],
    ["총 공부시간",fmt(totalTime)],
    ["총 시험",totalTests+"회"],
    ["푼 절 수",solved+"절"],
    ["404절 달성률",Math.round(mastered/404*1000)/10+"%"]
  ]);
  const achievements=[
    ["📖 404절 등록 완료", all.length>=404],
    ["🥉 첫 시험 완료", totalTests>=1],
    ["🥈 100문제 풀이", solved>=100],
    ["🥇 1,000문제 풀이", solved>=1000],
    ["🔥 7일 연속 학습", st.best>=7],
    ["🏆 30일 연속 학습", st.best>=30],
    ["⏰ 10시간 공부", totalTime>=36000],
    ["🎯 정답률 90% 달성", solved>=20 && correct/solved>=0.9]
  ];
  el.achievements.innerHTML=achievements.map(([name,done])=>`<div class="item achievement ${done?"":"locked"}"><b>${name}</b><span>${done?"달성":"미달성"}</span></div>`).join("");
}


