function updatePrayerTitleField(){
  if(!el.prayerTitleWrap || !el.prayerTitleInput)return;
  const show=el.prayerType.value==="기도제목";
  el.prayerTitleWrap.classList.toggle("hidden", !show);
  if(!show)el.prayerTitleInput.value="";
}

function savePrayer(textOverride){
  const text=(textOverride||el.prayerText.value).trim();
  const title=el.prayerType.value==="기도제목" ? (el.prayerTitleInput?.value||"").trim() : "";

  if(!text && !title){
    alert("내용을 입력해주세요.");
    return;
  }

  const list=prayers();
  const editId=el.prayerEditId ? el.prayerEditId.value : "";

  if(editId){
    const item=list.find(p=>String(p.id)===String(editId));
    if(item){
      item.type=el.prayerType.value;
      item.status=el.prayerStatus.value;
      item.title=title;
      item.text=text;
      item.updatedAt=Date.now();
      item.updatedDate=new Date().toLocaleDateString("ko-KR");
      if(item.status==="응답/완료" && !item.answeredDate){
        item.answeredAt=Date.now();
        item.answeredDate=new Date().toLocaleDateString("ko-KR");
      }
    }
    clearPrayerEditor();
  }else{
    list.unshift({
      id:Date.now(),
      type:el.prayerType.value,
      status:el.prayerStatus.value,
      title,
      text,
      date:new Date().toLocaleDateString("ko-KR"),
      createdAt:Date.now(),
      pinned:false,
      answeredAt:el.prayerStatus.value==="응답/완료"?Date.now():null,
      answeredDate:el.prayerStatus.value==="응답/완료"?new Date().toLocaleDateString("ko-KR"):""
    });
    clearPrayerEditor();
  }

  set(K.prayers,list);
  if(el.reflectionText)el.reflectionText.value="";
  renderAll();
}

function clearPrayerEditor(){
  if(el.prayerEditId)el.prayerEditId.value="";
  if(el.prayerTitleInput)el.prayerTitleInput.value="";
  if(el.prayerText)el.prayerText.value="";
  if(el.prayerType)el.prayerType.value="기도제목";
  if(el.prayerStatus)el.prayerStatus.value="진행중";
  updatePrayerTitleField();

  if(el.savePrayerBtn)el.savePrayerBtn.textContent="저장";
  if(el.cancelPrayerEditBtn)el.cancelPrayerEditBtn.classList.add("hidden");
}

function renderPrayer(){
  if(!el.prayerList)return;
  let list=prayers();

  const keyword=(el.prayerSearchInput?.value||"").trim();
  const filter=el.prayerFilterSelect?.value||"all";

  if(keyword){
    list=list.filter(p=>(p.text||"").includes(keyword) || (p.title||"").includes(keyword) || (p.type||"").includes(keyword) || (p.status||"").includes(keyword));
  }
  if(filter!=="all"){
    list=list.filter(p=>p.status===filter || p.type===filter);
  }

  list=[...list].sort((a,b)=>{
    if(!!b.pinned!==!!a.pinned)return (b.pinned?1:0)-(a.pinned?1:0);
    return (b.createdAt||b.id||0)-(a.createdAt||a.id||0);
  });

  el.prayerList.innerHTML=list.map(p=>`
    <div class="item prayerItem ${p.status==="응답/완료"?"answered":""}">
      <div class="prayerHead">
        <div>
          <b>${p.pinned?"📌 ":""}${esc(p.type)}${p.title?` · ${esc(p.title)}`:""}</b>
          <span class="badge">${esc(p.status)}</span>
          <span class="badge">작성 ${esc(p.date||"-")}</span>
          ${p.updatedDate?`<span class="badge">수정 ${esc(p.updatedDate)}</span>`:""}
          ${p.answeredDate?`<span class="badge">응답 ${esc(p.answeredDate)}</span>`:""}
        </div>
      </div>
      ${p.text?`<div class="prayerTextView">${esc(p.text)}</div>`:""}
      <div class="smallBtns">
        <button class="secondary" onclick="editPrayer(${p.id})">✏️ 수정</button>
        <button class="secondary" onclick="togglePrayerAnswered(${p.id})">${p.status==="응답/완료"?"↩️ 진행중":"✅ 응답 완료"}</button>
        <button class="secondary" onclick="togglePrayerPin(${p.id})">${p.pinned?"📌 고정 해제":"📌 고정"}</button>
        <button class="ghost danger" onclick="deletePrayer(${p.id})">🗑 삭제</button>
      </div>
    </div>
  `).join("") || "<p class='note'>저장한 기도 제목이나 묵상이 없습니다.</p>";
}

