function recordQuestionCount(r){
  return Number(r.count ?? r.total ?? r.questionCount ?? 0) || 0;
}
function isExamRecord(r){
  const mode=String(r?.mode||"");
  return recordQuestionCount(r)>0 && !mode.includes("본문 읽기");
}

function countMemorizedVerses(){
  return verses().filter(isVerseMemorized).length;
}

function wrongNoteStats(){
  const list=wrongNoteVerses(true);
  const active=list.filter(v=>isWrongForNote(v));
  const activeKeys=new Set(active.map(v=>key(v)));
  const resolved=list.filter(v=>!activeKeys.has(key(v)));
  const rate=(active.length+resolved.length)?Math.round(resolved.length/(active.length+resolved.length)*100):0;
  return {active,resolved,rate,total:active.length+resolved.length};
}

function countReadChapters(){
  const chapters=new Set(records().filter(r=>String(r.mode||"").includes("본문 읽기")).map(r=>{
    const m=String(r.mode||"").match(/(\d+)장/);
    return m?Number(m[1]):null;
  }).filter(Boolean));
  return chapters.size;
}

function totalSolvedQuestions(){
  return records().filter(isExamRecord).reduce((sum,r)=>sum+recordQuestionCount(r),0);
}

function bestAccuracy(){
  const rs=records().filter(isExamRecord).filter(r=>typeof r.accuracy==="number" || !isNaN(Number(r.accuracy)));
  return rs.length?Math.max(...rs.map(r=>Number(r.accuracy)||0)):0;
}

function achievementDefinitions(){
  const memCount=countMemorizedVerses();
  const recs=records();
  const examRecs=recs.filter(isExamRecord);
  const solved=totalSolvedQuestions();
  const completedChapters=[...Array(22)].filter((_,i)=>{
    const ch=i+1;
    const arr=verses().filter(v=>v.chapter===ch);
    return arr.length && arr.every(isVerseMemorized);
  }).length;

  return [
    {icon:"🥇",title:"첫 시험 완료",done:examRecs.length>=1,desc:examRecs.length>=1?"달성 완료":"시험 기록 1회 이상"},
    {icon:"📝",title:"시험 100문제 풀이",done:solved>=100,desc:`${solved}/100문제`},
    {icon:"📖",title:"50절 암기",done:memCount>=50,desc:`${memCount}/50절`},
    {icon:"📖",title:"100절 암기",done:memCount>=100,desc:`${memCount}/100절`},
    {icon:"📖",title:"200절 암기",done:memCount>=200,desc:`${memCount}/200절`},
    {icon:"📖",title:"300절 암기",done:memCount>=300,desc:`${memCount}/300절`},
    {icon:"📖",title:"400절 암기",done:memCount>=400,desc:`${memCount}/400절`},
    {icon:"✨🏆",title:"404절 암기",done:memCount>=404,desc:`${memCount}/404절`},
    {icon:"👑",title:"장 100% 완료",done:completedChapters>=1,desc:`${completedChapters}/22장`}
  ];
}

function renderAchievements(){
  const box=document.getElementById("achievementList");
  if(!box)return;
  const defs=achievementDefinitions();
  box.innerHTML=defs.map(a=>`<div class="achievementBadge ${a.done?"done":"locked"}">
    <div class="achievementIcon">${a.icon}</div>
    <div><b>${a.title}</b><br><span class="note">${a.done?"달성 완료":a.desc}</span></div>
  </div>`).join("");
}

function renderStudyTimeline(){
  const box=document.getElementById("studyTimelineList");
  if(!box)return;
  const items=[];

  records().slice(0,30).forEach(r=>{
    const date=r.dateISO||String(r.date||"").slice(0,10)||"날짜 없음";
    const total=recordQuestionCount(r);
    const correct=Number(r.correct)||0;
    const wrong=Number(r.wrong)||0;
    const mode=r.mode||"학습";
    let text="";
    if(String(mode).includes("본문 읽기")){
      text=`📖 ${mode}${r.durationText?` · ${r.durationText}`:""}`;
    }else{
      text=`📝 ${mode} · ${total}문제 · 정답 ${correct} · 오답 ${wrong}`;
    }
    items.push({date,text});
  });

  verses().filter(v=>(mem()[key(v)]||{}).manualMemorizedAt).forEach(v=>{
    const r=mem()[key(v)]||{};
    items.push({date:r.manualMemorizedAt,text:`✅ 계 ${v.chapter}:${v.verse} 암기 체크`});
  });

  const grouped={};
  items.sort((a,b)=>String(b.date).localeCompare(String(a.date))).slice(0,40).forEach(it=>{
    grouped[it.date]=grouped[it.date]||[];
    grouped[it.date].push(it.text);
  });

  const dates=Object.keys(grouped).sort((a,b)=>String(b).localeCompare(String(a))).slice(0,7);
  if(!dates.length){
    box.innerHTML="<p class='note'>아직 표시할 공부 기록이 없습니다.</p>";
    return;
  }
  box.innerHTML=dates.map(d=>`<div class="item timelineDay"><b>${d}</b><br>${grouped[d].slice(0,8).map(t=>`<div class="timelineLine">${esc(t)}</div>`).join("")}</div>`).join("");
}

